<script>
// Add global flag to track Quill loading
window.quillReady = false;

// Custom Quill font size configuration using classes (better compatibility)
var SizeClass = Quill.import('attributors/class/size');
SizeClass.whitelist = ['10px', '12px', '14px', '16px', '18px', '20px', '24px', '28px', '32px', '36px', '48px'];
Quill.register(SizeClass, true);

// Custom font family configuration using classes
var FontClass = Quill.import('attributors/class/font');

// Default system fonts
var defaultFonts = ['arial', 'helvetica', 'times', 'georgia', 'verdana', 'courier', 'outfit'];

// Add custom uploaded fonts from database
@if(isset($customFonts) && $customFonts->count() > 0)
var customFonts = [
    @foreach($customFonts as $font)
    '{{ $font->font_family }}',
    @endforeach
];
@else
var customFonts = [];
@endif

// Combine default and custom fonts
FontClass.whitelist = defaultFonts.concat(customFonts);
Quill.register(FontClass, true);

console.log('Quill fonts loaded:', FontClass.whitelist);

window.addEventListener('load', function() {
    if (typeof Quill !== 'undefined') {
        window.quillReady = true;
        console.log('Quill is ready');
    }
});
</script>

