.ticket-mask {
        --mask: conic-gradient(from 45deg at left,#0000,#000 1deg 89deg,#0000 90deg) left/51% 16.00px repeat-y,conic-gradient(from -135deg at right,#0000,#000 1deg 89deg,#0000 90deg) 100% calc(50% + 8px)/51% 16.00px repeat-y;
        -webkit-mask: var(--mask);
        mask: var(--mask);
        padding: 1.5rem;
        background-color: #eee;
        border: unset;
    }

    .page {
      max-width: 100%;
      min-height: 1000px;
      margin: 0 auto;
      background: white;
      padding: 40px;
      box-shadow: 0 0 20px rgba(0,0,0,0.1);
      border-radius: 8px;
      --page-bg-color: {{ $data->background_color }}; /* CSS variable for dynamic page background */
    }
    
    .dropzone {
      min-height: 100px;
      border: 2px dashed var(--border-color);
      border-radius: 8px;
      margin: 10px 0;
      display: flex;
      align-items: center;
      justify-content: center;
      color: #666;
      transition: all 0.2s;
    }
    
    .dropzone.dragover {
      background: #f0f9ff;
      border-color: var(--primary-color);
    }
    
    /* Insertion zones between components */
    .insertion-zone {
      height: 8px;
      margin: 5px 0;
      border-radius: 4px;
      background: transparent;
      border: 2px dashed transparent;
      transition: all 0.2s ease;
      opacity: 0;
      position: relative;
    }
    
    .insertion-zone.drag-active {
      opacity: 1;
      background: #e3f2fd;
      border-color: #2196f3;
    }
    
    .insertion-zone.drag-over {
      height: 20px;
      background: #1976d2;
      border-color: #1976d2;
      box-shadow: 0 2px 8px rgba(25, 118, 210, 0.3);
    }
    
    .insertion-zone::before {
      content: "Drop here to insert";
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      font-size: 11px;
      color: #1976d2;
      background: #fff;
      padding: 2px 8px;
      border-radius: 12px;
      white-space: nowrap;
      opacity: 0;
      transition: opacity 0.2s ease;
    }
    
    .insertion-zone.drag-over::before {
      opacity: 1;
      color: #fff;
      background: rgba(255, 255, 255, 0.2);
    }
    
    /* SortableJS drag states */
    .sortable-ghost {
      opacity: 0.3;
    }
    
    .sortable-chosen {
      cursor: grabbing;
    }
    
    .sortable-drag {
      cursor: grabbing;
      transform: rotate(2deg);
    }
    
    .sortable-drag-over {
      background: #e3f2fd !important;
      border-color: #2196f3 !important;
    }
    
    .component {
      position: relative;
      padding: 10px;
      margin: 10px 0;
      border: 1px solid transparent;
      border-radius: 4px;
    }
    
    .component:hover {
      border-color: var(--primary-color);
    }
    
    .component.selected {
      outline: 2px solid var(--primary-color);
    }
    
    .component-controls {
      position: absolute;
      top: -30px;
      right: 0;
      display: none;
      background: white;
      border: 1px solid var(--border-color);
      border-radius: 4px;
      padding: 4px;
      z-index: 10;
    }
    
    .component:hover .component-controls {
      display: flex;
      gap: 4px;
    }
    
    .btn {
      padding: 4px 8px;
      background: var(--primary-color);
      color: white;
      border: none;
      border-radius: 4px;
      cursor: pointer;
      margin-bottom: 5px
    }
    
    .btn:hover {
      opacity: 0.9;
    }
    
    .properties {
      width: 300px;
      background: white;
      border-left: 1px solid var(--border-color);
      padding: 20px;
      overflow-y: auto;
    }
    
    .properties h3 {
