    /* Responsive Spacing Controls */
    .responsive-spacing-group {
        margin-bottom: 20px;
        border: 1px solid #e9ecef;
        border-radius: 8px;
        padding: 15px;
        background: #f8f9fa;
    }

    .spacing-header {
