    }

    .device-content.active {
        display: block;
    }

    .spacing-grid {
        display: grid;
        grid-template-columns: 1fr 1fr;
        gap: 8px;
    }

    .spacing-item {
        display: flex;
        flex-direction: column;
    }

    .spacing-item label {
        font-size: 11px;
        font-weight: 500;
        color: #6c757d;
        margin-bottom: 4px;
    }

    .spacing-item input {
        padding: 6px 8px;
        font-size: 12px;
        border: 1px solid #ced4da;
        border-radius: 4px;
        background: white;
    }

    .spacing-item input:focus {
        outline: none;
        border-color: #007bff;
        box-shadow: 0 0 0 2px rgba(0, 123, 255, 0.1);
    }
    
    .border-grid {
        display: grid;
        grid-template-columns: 1fr 1fr;
        gap: 8px;
    }

    .border-item {
        display: flex;
        flex-direction: column;
    }

    .border-item label {
        font-size: 11px;
        font-weight: 500;
        color: #6c757d;
        margin-bottom: 4px;
    }

    .border-item input,
