                htmlContent: '<div style="padding: 20px; text-align: center;"><h3>Custom HTML Content</h3><p>Add your custom HTML code in the properties panel</p></div>',
                height: '300'
            };
            
            content.renderCustomHtml = function() {
                const d = content.customHtmlData;
                if (!d) return;
                
                const iframeId = 'custom-html-iframe-' + Date.now() + Math.random().toString(36).substr(2, 9);
                
                // Add comprehensive link handler script
                const linkHandlerScript = '<script>' +
                    'document.addEventListener("click", function(e) {' +
                        'var target = e.target.closest("a[href]");' +
                        'if (!target) return;' +
                        'var href = target.getAttribute("href");' +
                        'if (!href || href === "#") return;' +
                        'var isInternal = href.startsWith("/") || href.startsWith("./") || href.startsWith("../") || href.includes(window.location.hostname) || !href.includes("://");' +
                        'if (isInternal) {' +
                            'e.preventDefault();' +
                            'e.stopPropagation();' +
                            'try {' +
                                'window.top.location.href = href;' +
                            '} catch(e2) {' +
                                'try {' +
                                    'window.parent.location.href = href;' +
                                '} catch(e3) {' +
                                    'window.open(href, "_blank");' +
                                '}' +
                            '}' +
                        '}' +
                    '}, true);' +
                    'document.addEventListener("submit", function(e) {' +
                        'var form = e.target;' +
                        'var action = form.getAttribute("action");' +
                        'if (action && !action.includes("://")) {' +
                            'e.preventDefault();' +
                            'try {' +
                                'window.top.location.href = action;' +
                            '} catch(e2) {' +
                                'try {' +
                                    'window.parent.location.href = action;' +
                                '} catch(e3) {}' +
                            '}' +
                        '}' +
                    '}, true);' +
                '<\/script>';
                
                const htmlWithScript = d.htmlContent + linkHandlerScript;
                const escapedHtml = htmlWithScript.split('"').join('&quot;');
                
                content.innerHTML = 
                    '<div class="custom-html-preview" style="border: 2px dashed #ccc; padding: 10px; background: #f9f9f9;">' +
                        '<div style="background: #667eea; color: white; padding: 5px 10px; margin-bottom: 10px; font-size: 12px; border-radius: 4px;">' +
                            '<i class="fas fa-code"></i> Custom HTML Component (Preview)' +
                        '</div>' +
                        '<iframe ' +
                            'id="' + iframeId + '" ' +
                            'srcdoc="' + escapedHtml + '" ' +
                            'style="width: 100%; border: none; background: white; display: block; min-height: ' + d.height + 'px;" ' +
                            'sandbox="allow-scripts allow-same-origin allow-top-navigation allow-popups" ' +
                            'scrolling="no">' +
                        '</iframe>' +
                    '</div>';
                
                // Auto-resize iframe to fit content
                setTimeout(() => {
                    const iframe = document.getElementById(iframeId);
                    if (iframe) {
                        try {
                            const resizeIframe = () => {
                                const iframeDoc = iframe.contentDocument || iframe.contentWindow.document;
                                if (iframeDoc && iframeDoc.body) {
                                    const height = Math.max(
                                        iframeDoc.body.scrollHeight,
                                        iframeDoc.documentElement.scrollHeight,
                                        parseInt(d.height) || 300
                                    );
                                    iframe.style.height = height + 'px';
                                }
                            };
                            
                            iframe.addEventListener('load', resizeIframe);
                            resizeIframe();
                            
                            // Periodic resize for dynamic content
                            const resizeInterval = setInterval(() => {
                                if (!document.body.contains(iframe)) {
                                    clearInterval(resizeInterval);
                                    return;
                                }
                                resizeIframe();
                            }, 500);
                        } catch (e) {
                            console.warn('Could not auto-resize iframe:', e);
                        }
                    }
                }, 100);
            };
            
            content.renderCustomHtml();
        break;

