            const textElement = content.querySelector('[id^="text-content-"]');
            const textContent = textElement ? textElement.innerHTML : content.textContent;
            const textEditorId = 'text-editor-' + Date.now();
            ckeditorinitTextBox(textEditorId);
            specificControls = `
                <div class="form-group">
                    <label>Content</label>
                    <textarea id="${textEditorId}" class="ck5-inline-editor" style="border: 1px solid #ddd; min-height: 100px; padding: 10px;">${textContent}</textarea>
                </div>
                <div class="form-group">
                    <label>Background Color</label>
                    <input type="color" value="${content.style.backgroundColor || '#ffffff'}" onchange="updateStyleProperty('backgroundColor', this.value)">
                </div>
            `;

            break;

            case 'inner-section':
            const innerSectionData = content._innerSectionData || {};
            const websiteType = document.getElementById('website_type')?.value || 'fundraiser';
            
            // Add to Menu option only for investment websites
            const menuOption = websiteType === 'investment' ? `
                <div class="form-group" style="border: 2px solid #007bff; border-radius: 8px; padding: 15px; margin-bottom: 20px; background-color: #f8f9ff;">
                    <h5 style="color: #007bff; margin-bottom: 10px;">
                        <i class="fas fa-bars"></i> Navigation Menu
                    </h5>
                    <label>
                        <input type="checkbox" ${innerSectionData.addToMenu ? 'checked' : ''} onchange="updateInnerSectionField(this.checked, 'addToMenu'); updateMenuSection(this.checked)">
                        Add this section to navigation menu
                    </label>
                    <small class="text-muted d-block mt-2">When enabled, this section will appear in the website's navigation menu for smooth scrolling.</small>
                    
                    <div class="mt-3" style="display: ${innerSectionData.addToMenu ? 'block' : 'none'};" id="menuTitleGroup">
                        <label>Menu Title</label>
                        <input type="text" value="${innerSectionData.menuTitle || ''}" onchange="updateInnerSectionField(this.value, 'menuTitle')" placeholder="e.g., About Us, Services, Contact">
                        <small class="text-muted">This text will appear in the navigation menu</small>
                    </div>
                    
                    <div class="mt-3" style="display: ${innerSectionData.addToMenu ? 'block' : 'none'};" id="sectionIdGroup">
                        <label>Section ID (Auto-generated)</label>
                        <input type="text" value="${innerSectionData.sectionId || ''}" readonly style="background-color: #f8f9fa;">
                        <small class="text-muted">This ID is used for navigation links. Auto-generated from menu title.</small>
                    </div>
                </div>
            ` : '';
            
            specificControls = `
                ${menuOption}
                <div class="form-group">
                    <label>Number of Columns</label>
                    <select onchange="updateInnerSectionColumns(this.value)">
                        <option value="1" ${innerSectionData.columns === 1 ? 'selected' : ''}>1 Column</option>
                        <option value="2" ${innerSectionData.columns === 2 ? 'selected' : ''}>2 Columns</option>
                        <option value="3" ${innerSectionData.columns === 3 ? 'selected' : ''}>3 Columns</option>
                        <option value="4" ${innerSectionData.columns === 4 ? 'selected' : ''}>4 Columns</option>
                        <option value="5" ${innerSectionData.columns === 5 ? 'selected' : ''}>5 Columns</option>
                        <option value="6" ${innerSectionData.columns === 6 ? 'selected' : ''}>6 Columns</option>
                    </select>
                    <small class="text-muted">Responsive breakpoints:</small>
                    <small class="text-muted">• Desktop (lg): Full columns</small>
                    <small class="text-muted">• Tablet (md): 2 columns max</small>
                    <small class="text-muted">• Mobile (sm): 1 column stacked</small>
                </div>
                <div class="form-group">
                    <label>Column Gap</label>
                    <input type="text" value="${innerSectionData.gap || '15px'}" onchange="updateInnerSectionGap(this.value)">
                    <small>Spacing between columns (e.g., 10px, 1rem, 20px)</small>
                </div>
                
                <h4 style="margin: 20px 0 10px 0; color: #333;">Layout Settings</h4>
                <div class="form-group">
                    <label>
                        <input type="checkbox" ${innerSectionData.fullWidth ? 'checked' : ''} onchange="updateInnerSectionField(this.checked, 'fullWidth')">
                        Stretch to Full Width
                    </label>
                    <small class="text-muted">Make this section span the full width of the page (like Elementor)</small>
                </div>
                <div class="form-group" style="display: ${innerSectionData.fullWidth ? 'block' : 'none'};" id="contentWidthGroup">
                    <label>Content Width</label>
                    <select onchange="updateInnerSectionField(this.value, 'contentWidth')">
                        <option value="full" ${innerSectionData.contentWidth === 'full' ? 'selected' : ''}>Full Width (components spread across full width)</option>
                        <option value="boxed" ${innerSectionData.contentWidth === 'boxed' ? 'selected' : ''}>Boxed (components stay centered)</option>
                    </select>
                    <small class="text-muted">Choose how content should behave within the full-width section</small>
                </div>
                
                <h4 style="margin: 20px 0 10px 0; color: #333;">Background Settings</h4>
                <div class="form-group">
                    <label>Background Type</label>
                    <select onchange="updateInnerSectionField(this.value, 'backgroundType'); toggleInnerSectionBackgroundType(this.value)">
                        <option value="color" ${innerSectionData.backgroundType === 'color' ? 'selected' : ''}>Color</option>
                        <option value="image" ${innerSectionData.backgroundType === 'image' ? 'selected' : ''}>Image</option>
                        <option value="video" ${innerSectionData.backgroundType === 'video' ? 'selected' : ''}>Video</option>
                    </select>
                </div>
                
                <div class="form-group" id="innerSectionBackgroundColor" style="display: ${innerSectionData.backgroundType === 'image' ? 'none' : 'block'};">
                    <label>Background Color</label>
                    <input type="color" value="${innerSectionData.backgroundColor || '#f8f9fa'}" onchange="updateInnerSectionField(this.value, 'backgroundColor')">
                </div>
                
                <div id="innerSectionBackgroundImageSettings" style="display: ${innerSectionData.backgroundType === 'image' ? 'block' : 'none'};">
                    <div class="form-group">
                        <label>Upload Background Image</label>
                        <input type="file" accept="image/*" onchange="uploadInnerSectionBackgroundImage(event)">
                        <small style="display: block; color: #666; margin-top: 6px;">Accepted: JPEG, PNG, GIF, WebP, SVG • Max: 2MB</small>
                        ${innerSectionData.backgroundImage ? `<div style="margin-top: 8px;"><img src="${innerSectionData.backgroundImage}" style="max-width: 100%; max-height: 100px; border-radius: 4px; border: 1px solid #ddd;"></div>` : ''}
                        <small class="text-muted" style="display: block; margin-top: 8px;">Use the parallax component for parallax effects</small>
                    </div>
                </div>

                <div id="innerSectionBackgroundVideoSettings" style="display: ${innerSectionData.backgroundType === 'video' ? 'block' : 'none'};}">
                    <div class="form-group">
                        <label>Upload Background Video</label>
                        <input type="file" accept="video/*" onchange="uploadInnerSectionBackgroundVideo(event)">
                        <small style="display: block; color: #666; margin-top: 6px;">Accepted: MP4, WebM, OGG • Max: 50MB</small>
                        ${innerSectionData.backgroundVideoUrl && !innerSectionData.backgroundVideoUrl.includes('youtu') ? `<div style="margin-top: 8px; padding: 8px; background:#f0f0f0; border-radius:4px;"><small style="color:#666;">✓ Video uploaded (${innerSectionData.backgroundVideoType.toUpperCase()})</small></div>` : ''}
                    </div>
                    <div class="form-group" style="border-top: 1px solid #ddd; padding-top: 10px;">
                        <label style="font-weight: 600; color: #666;">OR enter Video URL</label>
                        <input type="text" value="${innerSectionData.backgroundVideoUrl || ''}" onchange="updateInnerSectionField(this.value, 'backgroundVideoUrl'); if (getContentElement(selectedComponent)?.updateBackground) { getContentElement(selectedComponent).updateBackground(); }" placeholder="https://example.com/video.mp4">
                        <small class="text-muted">Direct video URL (MP4/WebM/OGG). For YouTube, paste the embed or share link.</small>
                    </div>
                    <div class="form-group">
                        <label>Video Format</label>
                        <select onchange="updateInnerSectionField(this.value, 'backgroundVideoType'); if (getContentElement(selectedComponent)?.updateBackground) { getContentElement(selectedComponent).updateBackground(); }">
                            <option value="mp4" ${innerSectionData.backgroundVideoType === 'mp4' ? 'selected' : ''}>MP4</option>
                            <option value="webm" ${innerSectionData.backgroundVideoType === 'webm' ? 'selected' : ''}>WebM</option>
                            <option value="ogg" ${innerSectionData.backgroundVideoType === 'ogg' ? 'selected' : ''}>OGG</option>
                            <option value="youtube" ${innerSectionData.backgroundVideoType === 'youtube' ? 'selected' : ''}>YouTube Embed URL</option>
                        </select>
                    </div>
                    <div class="form-group" style="display:flex; gap:12px; flex-wrap:wrap;">
                        <label style="display:flex; align-items:center; gap:6px;">
                            <input type="checkbox" ${innerSectionData.backgroundVideoAutoplay !== false ? 'checked' : ''} onchange="updateInnerSectionField(this.checked, 'backgroundVideoAutoplay'); if (getContentElement(selectedComponent)?.updateBackground) { getContentElement(selectedComponent).updateBackground(); }"> Autoplay
                        </label>
                        <label style="display:flex; align-items:center; gap:6px;">
                            <input type="checkbox" ${innerSectionData.backgroundVideoLoop !== false ? 'checked' : ''} onchange="updateInnerSectionField(this.checked, 'backgroundVideoLoop'); if (getContentElement(selectedComponent)?.updateBackground) { getContentElement(selectedComponent).updateBackground(); }"> Loop
                        </label>
                        <label style="display:flex; align-items:center; gap:6px;">
                            <input type="checkbox" ${innerSectionData.backgroundVideoMuted !== false ? 'checked' : ''} onchange="updateInnerSectionField(this.checked, 'backgroundVideoMuted'); if (getContentElement(selectedComponent)?.updateBackground) { getContentElement(selectedComponent).updateBackground(); }"> Muted
                        </label>
                    </div>
                </div>
                
                <h4 style="margin: 20px 0 10px 0; color: #333;">Spacing</h4>
                <div class="form-group">
                    <label>Padding</label>
                    <input type="text" value="${innerSectionData.padding || '20px'}" onchange="updateInnerSectionField(this.value, 'padding')">
                </div>
                <div class="form-group">
                    <label>Margin</label>
                    <input type="text" value="${innerSectionData.margin || '10px 0'}" onchange="updateInnerSectionField(this.value, 'margin')">
                </div>
                
                <h4 style="margin: 20px 0 10px 0; color: #333; border-top: 2px solid #667eea; padding-top: 15px;">
                    <i class="fas fa-magic"></i> Advanced Animations
                </h4>
                <div class="form-group">
                    <label>
                        <input type="checkbox" ${innerSectionData.animationEnabled ? 'checked' : ''} onchange="updateInnerSectionField(this.checked, 'animationEnabled'); toggleAnimationSettings(this.checked)">
                        Enable Animations
                    </label>
                    <small class="text-muted">Trigger animations when section enters viewport</small>
                </div>
                
                <div id="animationSettings" style="display: ${innerSectionData.animationEnabled ? 'block' : 'none'}; border-left: 3px solid #667eea; padding-left: 15px; margin-left: 5px;">
                    <div class="form-group">
                        <label>Animation Type</label>
                        <select onchange="updateInnerSectionField(this.value, 'animationType')">
                            <option value="none" ${innerSectionData.animationType === 'none' ? 'selected' : ''}>None</option>
                            <optgroup label="Slide Animations">
                                <option value="slideLeft" ${innerSectionData.animationType === 'slideLeft' ? 'selected' : ''}>Slide In from Left</option>
                                <option value="slideRight" ${innerSectionData.animationType === 'slideRight' ? 'selected' : ''}>Slide In from Right</option>
                                <option value="slideUp" ${innerSectionData.animationType === 'slideUp' ? 'selected' : ''}>Slide In from Bottom</option>
                                <option value="slideDown" ${innerSectionData.animationType === 'slideDown' ? 'selected' : ''}>Slide In from Top</option>
                            </optgroup>
                            <optgroup label="Fade Animations">
                                <option value="fade" ${innerSectionData.animationType === 'fade' ? 'selected' : ''}>Fade In</option>
                                <option value="fadeZoom" ${innerSectionData.animationType === 'fadeZoom' ? 'selected' : ''}>Fade In + Zoom</option>
                                <option value="fadeBlur" ${innerSectionData.animationType === 'fadeBlur' ? 'selected' : ''}>Fade In + Blur</option>
                            </optgroup>
                            <optgroup label="Special Effects">
                                <option value="bounce" ${innerSectionData.animationType === 'bounce' ? 'selected' : ''}>Bounce In</option>
                                <option value="flip" ${innerSectionData.animationType === 'flip' ? 'selected' : ''}>Flip In</option>
                                <option value="rotate" ${innerSectionData.animationType === 'rotate' ? 'selected' : ''}>Rotate In</option>
                            </optgroup>
                        </select>
                    </div>
                    
                    <div class="form-group">
                        <label>Animation Duration (seconds)</label>
                        <input type="range" min="0.3" max="2" step="0.1" value="${innerSectionData.animationDuration || '0.8'}" 
                               onchange="updateInnerSectionField(this.value, 'animationDuration'); this.nextElementSibling.textContent = this.value + 's'">
                        <span style="margin-left: 10px; font-weight: bold;">${innerSectionData.animationDuration || '0.8'}s</span>
                        <small class="text-muted">How long the animation takes to complete</small>
                    </div>
                    
                    <div class="form-group">
                        <label>Section Delay (seconds)</label>
                        <input type="range" min="0" max="2" step="0.1" value="${innerSectionData.animationDelay || '0'}" 
                               onchange="updateInnerSectionField(this.value, 'animationDelay'); this.nextElementSibling.textContent = this.value + 's'">
                        <span style="margin-left: 10px; font-weight: bold;">${innerSectionData.animationDelay || '0'}s</span>
                        <small class="text-muted">Delay before section animation starts</small>
                    </div>
                    
                    <div class="form-group">
                        <label>Column Stagger Delay (seconds)</label>
                        <input type="range" min="0" max="1" step="0.05" value="${innerSectionData.staggerDelay || '0.15'}" 
                               onchange="updateInnerSectionField(this.value, 'staggerDelay'); this.nextElementSibling.textContent = this.value + 's'">
                        <span style="margin-left: 10px; font-weight: bold;">${innerSectionData.staggerDelay || '0.15'}s</span>
                        <small class="text-muted">Delay between each column animation (creates sequence effect)</small>
                    </div>
                    
                    <div class="form-group">
                        <label>Animation Easing</label>
                        <select onchange="updateInnerSectionField(this.value, 'animationEasing')">
                            <option value="ease" ${innerSectionData.animationEasing === 'ease' ? 'selected' : ''}>Ease (default)</option>
                            <option value="ease-in" ${innerSectionData.animationEasing === 'ease-in' ? 'selected' : ''}>Ease In</option>
                            <option value="ease-out" ${innerSectionData.animationEasing === 'ease-out' ? 'selected' : ''}>Ease Out</option>
                            <option value="ease-in-out" ${innerSectionData.animationEasing === 'ease-in-out' ? 'selected' : ''}>Ease In Out</option>
                            <option value="linear" ${innerSectionData.animationEasing === 'linear' ? 'selected' : ''}>Linear</option>
                            <option value="cubic-bezier(0.68, -0.55, 0.265, 1.55)" ${innerSectionData.animationEasing === 'cubic-bezier(0.68, -0.55, 0.265, 1.55)' ? 'selected' : ''}>Bounce</option>
                        </select>
                        <small class="text-muted">Animation timing function</small>
                    </div>
                    
                    <div class="form-group">
                        <label>
                            <input type="checkbox" ${innerSectionData.animationLoop ? 'checked' : ''} onchange="updateInnerSectionField(this.checked, 'animationLoop')">
                            Loop Animation (repeat on every view)
                        </label>
                        <small class="text-muted">If unchecked, animation plays once only</small>
                    </div>
                </div>
                
                <h4 style="margin: 20px 0 10px 0; color: #333;">
                    <i class="fas fa-mountain"></i> Parallax Effect
                </h4>
                <div class="form-group">
                    <label>
                        <input type="checkbox" ${innerSectionData.parallaxEnabled ? 'checked' : ''} onchange="updateInnerSectionField(this.checked, 'parallaxEnabled'); toggleParallaxSettings(this.checked)">
                        Enable Parallax Scrolling
                    </label>
                    <small class="text-muted">Background moves slower than content (depth effect)</small>
                </div>
                
                <div id="parallaxSettings" style="display: ${innerSectionData.parallaxEnabled ? 'block' : 'none'}; border-left: 3px solid #28a745; padding-left: 15px; margin-left: 5px;">
                    <div class="form-group">
                        <label>Parallax Speed</label>
                        <input type="range" min="0.1" max="1" step="0.1" value="${innerSectionData.parallaxSpeed || '0.5'}" 
                               onchange="updateInnerSectionField(this.value, 'parallaxSpeed'); this.nextElementSibling.textContent = this.value">
                        <span style="margin-left: 10px; font-weight: bold;">${innerSectionData.parallaxSpeed || '0.5'}</span>
                        <small class="text-muted">Lower = slower movement (0.5 = half speed)</small>
                    </div>
                    <small style="color: #856404; background: #fff3cd; padding: 10px; border-radius: 4px; display: block; margin-top: 10px;">
                        <i class="fas fa-info-circle"></i> <strong>Note:</strong> Parallax works best with background images and requires background attachment to be "scroll"
                    </small>
                </div>
            `;
            break;

            case 'heading':
            specificControls = `
                <div class="form-group">
                <label>Heading Level</label>
                <select onchange="updateHeadingLevel(this.value)">
                    <option value="h1" ${content.tagName === 'H1' ? 'selected' : ''}>H1</option>
                    <option value="h2" ${content.tagName === 'H2' ? 'selected' : ''}>H2</option>
                    <option value="h3" ${content.tagName === 'H3' ? 'selected' : ''}>H3</option>
                    <option value="h4" ${content.tagName === 'H4' ? 'selected' : ''}>H4</option>
                </select>
                </div>
            `;
            break;

            case 'auction-list':
            specificControls = `
                <div class="form-group">
                    <label>Background Color</label>
                    <input type="color" value="${rgbToHex(content.style.backgroundColor || '#ffffff')}" onchange="updateStyle(this, 'backgroundColor')">
                    <small class="text-muted">Background behind the auction list</small>
                </div>
                <div class="form-group">
                    <label>Auction List Settings</label>
                    <p>This component displays live auction items from your auction system.</p>
                </div>
                <div class="form-group">
                    <label>Items per Row</label>
                    <select onchange="updateAuctionListColumns(this.value)">
                        <option value="1">1 Column</option>
                        <option value="2">2 Columns</option>
                        <option value="3" selected>3 Columns</option>
                        <option value="4">4 Columns</option>
                    </select>
                </div>
                <div class="form-group">
                    <label>Show Starting Bid</label>
                    <input type="checkbox" checked onchange="toggleAuctionStartingBid(this.checked)">
                </div>
            `;
            break;

            case 'section-title':
            const sectionTitleElement = content.querySelector('[id^="section-title-content-"]');
            const sectionTitleContent = sectionTitleElement ? sectionTitleElement.innerHTML : content.textContent;
            const sectionTitleEditorId = 'section-title-editor-' + Date.now();
            ckeditorinitTextBox(sectionTitleEditorId);
            specificControls = `
                <div class="form-group">
                    <label>Section Title Content</label>
                    <textarea id="${sectionTitleEditorId}" class="quill-editor" style="border: 1px solid #ddd; min-height: 100px; padding: 10px;">${sectionTitleContent}</textarea>
                </div>
                <div class="form-group">
                    <label>Background Color</label>
                    <input type="color" value="${rgbToHex(content.style.backgroundColor || '#ffffff')}" onchange="updateStyle(this, 'backgroundColor')">
                </div>
                <div class="form-group">
                <small class="text-muted">💡 Use the formatting toolbar above to style your section title with headings (H1-H5), fonts, colors, and more.</small>
                </div>
            `;
            break;

            case 'divider':
            specificControls = `
                <div class="form-group">
                <label>Divider Thickness</label>
                <input type="text" value="${content.style.height || '2px'}" onchange="updateStyle(this, 'height')">
                </div>
                <div class="form-group">
                <label>Color</label>
                <input type="color" value="${rgbToHex(content.style.backgroundColor || '#000000')}" onchange="updateStyle(this, 'backgroundColor')">
                </div>
            `;
            break;

            case 'site-banner':
            case 'custom-banner':
                const bannerData = content._customBannerData || {
                    imgSrc: '',
                    title: 'Custom Banner Title',
                    subtitle: 'Custom Banner Subtitle',
                    titleShadow: '0 2px 8px rgba(0,0,0,0.5)',
                    subtitleShadow: '0 2px 8px rgba(0,0,0,0.5)',
                    titleColor: '#ffffff',
                    subtitleColor: '#ffffff',
                    titleFontSize: '2.2em',
                    subtitleFontSize: '1.2em',
                    textAlign: 'center'
                };
                specificControls = `
                    <div class="form-group">
                        <label>Background Color</label>
                        <input type="color" value="${rgbToHex(content.style.backgroundColor || '#ffffff')}" onchange="updateStyle(this, 'backgroundColor')">
                        <small class="text-muted">Background behind the banner</small>
                    </div>
                    <div class="form-group">
                        <label>Banner Image</label>
                        <input type="file" accept="image/*" onchange="uploadCustomBannerImage(event)">
                        <small style="display: block; color: #666; margin-top: 6px;">Accepted: JPEG, PNG, GIF, WebP, SVG • Max: 2MB</small>
                    </div>
                    <div class="form-group">
                        <label>Banner Title</label>
                        <input type="text" value="${bannerData.title || ''}" onchange="updateCustomBannerField(this.value, 'title')">
                    </div>
                    <div class="form-group">
                        <label>Title Color</label>
                        <input type="color" value="${bannerData.titleColor || '#ffffff'}" onchange="updateCustomBannerField(this.value, 'titleColor')">
                    </div>
                    <div class="form-group">
                        <label>Title Font Size</label>
                        <input type="text" value="${bannerData.titleFontSize || '2.2em'}" onchange="updateCustomBannerField(this.value, 'titleFontSize')">
                    </div>
                    <div class="form-group">
                        <label>Banner Subtitle</label>
                        <input type="text" value="${bannerData.subtitle || ''}" onchange="updateCustomBannerField(this.value, 'subtitle')">
                    </div>
                    <div class="form-group">
                        <label>Subtitle Color</label>
                        <input type="color" value="${bannerData.subtitleColor || '#ffffff'}" onchange="updateCustomBannerField(this.value, 'subtitleColor')">
                    </div>
                    <div class="form-group">
                        <label>Subtitle Font Size</label>
                        <input type="text" value="${bannerData.subtitleFontSize || '1.2em'}" onchange="updateCustomBannerField(this.value, 'subtitleFontSize')">
                    </div>
                    <div class="form-group">
                        <label>Title Drop Shadow</label>
                        <input type="text" value="${bannerData.titleShadow || ''}" onchange="updateCustomBannerField(this.value, 'titleShadow')">
                        <small>e.g. 0 2px 8px rgba(0,0,0,0.5)</small>
                    </div>
                    <div class="form-group">
                        <label>Subtitle Drop Shadow</label>
                        <input type="text" value="${bannerData.subtitleShadow || ''}" onchange="updateCustomBannerField(this.value, 'subtitleShadow')">
                        <small>e.g. 0 2px 8px rgba(0,0,0,0.5)</small>
                    </div>
                    <div class="form-group">
                        <label>Text Align</label>
                        <select onchange="updateCustomBannerField(this.value, 'textAlign')">
                            <option value="left" ${bannerData.textAlign === 'left' ? 'selected' : ''}>Left</option>
                            <option value="center" ${bannerData.textAlign === 'center' ? 'selected' : ''}>Center</option>
                            <option value="right" ${bannerData.textAlign === 'right' ? 'selected' : ''}>Right</option>
                        </select>
                    </div>
                `;
            break;

            case 'gallery':
                const galleryData = content._galleryData || { images: [], columns: 3 };
                specificControls = `
                    <div class="form-group">
                        <label>Upload Images</label>
                        <input type="file" accept="image/*" multiple onchange="uploadGalleryImages(event)">
                        <small style="display: block; color: #666; margin-top: 6px;">Accepted: JPEG, PNG, GIF, WebP, SVG • Max: 2MB per image</small>
                        <div style="margin-top:8px;">
                            ${galleryData.images.map((src, idx) => '<img src="' + src + '" style="width:60px;height:40px;object-fit:cover;border-radius:4px;margin-right:4px;cursor:pointer;" onclick="openGalleryModalFromPanel(' + idx + ')">').join('')}
                        </div>
                    </div>
                    <div class="form-group">
                        <label>Columns</label>
                        <input type="number" min="1" max="6" value="${galleryData.columns}" onchange="updateGalleryColumns(this.value)">
                    </div>
                    <div class="form-group">
                        <label>Background Color</label>
                        <input type="color" value="${rgbToHex(content.style.backgroundColor || '#ffffff')}" onchange="updateStyle(this, 'backgroundColor')">
                        <small class="text-muted">Background behind the gallery</small>
                    </div>
                `;
            break;
            case 'slider':
                const sliderData = content._sliderData || { images: [], slidesToShow: 1, slideSpeed: 2000, isMarquee: false };
                specificControls = `
                    <div class="form-group">
                        <label>Upload Images</label>
                        <input type="file" accept="image/*" multiple onchange="uploadSliderImages(event)">
                        <small style="display: block; color: #666; margin-top: 6px;">Accepted: JPEG, PNG, GIF, WebP, SVG • Max: 2MB per image</small>
                        <div style="margin-top:8px;display:flex;gap:4px;flex-wrap:wrap;">
                            ${sliderData.images.map((src, idx) => '<img src="' + src + '" style="width:60px;height:40px;object-fit:cover;border-radius:4px;cursor:pointer;" onclick="openSliderModalFromPanel(' + idx + ')">').join('')}
                        </div>
                    </div>
                    <div class="form-group">
                        <label>Slides to Show</label>
                        <input type="number" min="1" max="10" value="${sliderData.slidesToShow}" 
                               onchange="updateSliderSlidesToShow(this.value)"
                               onblur="updateSliderSlidesToShow(this.value)"
                               onkeypress="if(event.key==='Enter') { this.blur(); }">
                    </div>
                    <div class="form-group">
                        <label>Slide Speed (ms)</label>
                        <input type="number" min="500" max="10000" value="${sliderData.slideSpeed}" 
                               onchange="updateSliderSlideSpeed(this.value)"
                               onblur="updateSliderSlideSpeed(this.value)"
                               onkeypress="if(event.key==='Enter') { this.blur(); }">
                    </div>
                    <div class="form-group">
                        <label>Display Mode</label>
                        <select onchange="updateSliderMarqueeMode(this.value)" style="width: 100%; padding: 8px; border: 1px solid #ddd; border-radius: 4px;">
                            <option value="false" ${(sliderData.isMarquee === false || !sliderData.isMarquee) ? 'selected' : ''}>Regular Slider</option>
                            <option value="true" ${sliderData.isMarquee === true ? 'selected' : ''}>Continuous Marquee</option>
                        </select>
                        <small class="text-muted">Choose between standard slider or continuous scrolling marquee</small>
                    </div>
                    <div class="form-group">
                        <label>Background Color</label>
                        <input type="color" value="${rgbToHex(content.style.backgroundColor || '#ffffff')}" onchange="updateStyle(this, 'backgroundColor')">
                        <small class="text-muted">Background behind the slider</small>
                    </div>
                `;
            break;

            case 'visitor-upload':
            specificControls = `
                <div class="form-group">
                <label>Upload Label</label>
                <input type="text" value="${content.textContent}" onChange="updateContent(this.value)">
                </div>
            `;
            break;

            case 'video':
                const videoContainer = content.querySelector('.video-container');
                const currentUrl = content._videoData ? content._videoData.url : '';
                const currentType = content._videoData ? content._videoData.type : 'youtube';
                const autoplayEnabled = content._videoData ? content._videoData.autoplay : false;
                const showControls = content._videoData ? content._videoData.controls !== false : true;
                const currentWidth = content._videoData ? content._videoData.width : null;
                const currentHeight = content._videoData ? content._videoData.height : null;
                specificControls = `
                    <div class="form-group">
                        <label>Video Type</label>
                        <select onchange="switchVideoType(this.value)" id="videoTypeSelect">
                            <option value="youtube" ${currentType === 'youtube' ? 'selected' : ''}>YouTube Video</option>
                            <option value="uploaded" ${currentType === 'uploaded' ? 'selected' : ''}>Upload Video File</option>
                            <option value="custom" ${currentType === 'custom' ? 'selected' : ''}>Custom Video URL</option>
                        </select>
                    </div>
                    
                    <div id="youtubeControls" style="display: ${currentType === 'youtube' ? 'block' : 'none'};">
                        <div class="form-group">
                            <label>YouTube Video URL</label>
                            <input type="text" value="${currentType === 'youtube' ? currentUrl : ''}" onchange="updateVideoEmbed(this.value, 'youtube')" placeholder="https://www.youtube.com/watch?v=...">
                            <small class="text-muted">Paste a YouTube video URL</small>
                        </div>
                    </div>
                    
                    <div id="uploadControls" style="display: ${currentType === 'uploaded' ? 'block' : 'none'};">
                        <div class="form-group">
                            <label>Upload Video File</label>
                            <input type="file" accept="video/*" onchange="uploadVideoFile(event)" class="form-control mb-2">
                            <small style="display: block; color: #666; margin-top: 6px;">Accepted: MP4, WebM, OGG • Max: 50MB</small>
                            <input type="text" value="${currentType === 'uploaded' ? currentUrl : ''}" onchange="updateVideoEmbed(this.value, 'uploaded')" placeholder="Or enter video file URL" style="margin-top: 8px;">
                            <small class="text-muted" style="display: block; margin-top: 4px;">Or enter a direct video file URL</small>
                        </div>
                    </div>
                    
                    <div id="customControls" style="display: ${currentType === 'custom' ? 'block' : 'none'};">
                        <div class="form-group">
                            <label>Custom Video URL</label>
                            <input type="text" value="${currentType === 'custom' ? currentUrl : ''}" onchange="updateVideoEmbed(this.value, 'custom')" placeholder="https://example.com/video.mp4">
                            <small class="text-muted">Enter direct video URL (MP4, WebM, OGG, etc.)</small>
                        </div>
                        <div class="form-group">
                            <label>Video Format</label>
                            <select onchange="updateVideoFormat(this.value)" id="customVideoFormatSelect">
                                <option value="mp4" ${content._videoData?.videoFormat === 'mp4' ? 'selected' : ''}>MP4</option>
                                <option value="webm" ${content._videoData?.videoFormat === 'webm' ? 'selected' : ''}>WebM</option>
                                <option value="ogg" ${content._videoData?.videoFormat === 'ogg' ? 'selected' : ''}>OGG</option>
                            </select>
                            <small class="text-muted">Specify video format for optimal playback</small>
                        </div>
                    </div>
                    
                    <div class="form-group">
                        <label>
                            <input type="checkbox" ${autoplayEnabled ? 'checked' : ''} onchange="updateVideoAutoplay(this.checked)"> 
                            Enable Autoplay (Frontend Only)
                        </label>
                        <small class="text-muted">Video will autoplay when loaded on the frontend</small>
                    </div>

                    <div class="form-group">
                        <label>
                            <input type="checkbox" ${showControls ? 'checked' : ''} onchange="updateVideoControls(this.checked)"> 
                            Show Video Controls
                        </label>
                        <small class="text-muted">Hide this to remove the player's native controls</small>
                    </div>
                    
                    <div class="form-group">
                        <label>Background Color</label>
                        <input type="color" value="${rgbToHex(content.style.backgroundColor || '#ffffff')}" onchange="updateStyle(this, 'backgroundColor')">
                        <small class="text-muted">Background behind the video</small>
                    </div>
                    
                    <div class="row">
                        <div class="col-md-6">
                            <div class="form-group">
                                <label>Width (px)</label>
                                <input type="number" class="form-control" value="${currentWidth || ''}" onchange="updateVideoSize('width', this.value)" placeholder="Auto" min="100" max="1200">
                                <small class="text-muted">Leave empty for responsive width</small>
                            </div>
                        </div>
                        <div class="col-md-6">
                            <div class="form-group">
                                <label>Height (px)</label>
                                <input type="number" class="form-control" value="${currentHeight || ''}" onchange="updateVideoSize('height', this.value)" placeholder="Auto" min="100" max="800">
                                <small class="text-muted">Leave empty for responsive height</small>
                            </div>
                        </div>
                    </div>
                `;
                // Show current embed preview
                specificControls += `
                    <div class="form-group">
                        <label>Preview</label>
                        <div class="video-preview">${videoContainer.innerHTML}</div>
                    </div>
                `;
            break;

            case 'faq':
                const faqData = content._faqData || {
                    questions: [],
                    questionBackgroundColor: '#f3f4f6',
                    questionTextColor: '#1f2937',
                    answerBackgroundColor: '#ffffff',
                    answerTextColor: '#374151',
                    iconColor: '#059669',
                    borderRadius: '8px',
                    spacing: '10px'
                };
                
                specificControls = `
                    <div class="form-group">
                        <label>Background Color</label>
                        <input type="color" value="${rgbToHex(content.style.backgroundColor || '#ffffff')}" onchange="updateStyle(this, 'backgroundColor')">
                        <small class="text-muted">Background behind the entire FAQ section</small>
                    </div>
                    <h4 style="margin: 20px 0 10px 0; color: #333;">FAQ Questions</h4>
                    <div class="form-group">
                        <button type="button" onclick="addFaqQuestion()" style="background: #007bff; color: white; border: none; padding: 8px 16px; border-radius: 4px; cursor: pointer; margin-bottom: 10px;">
                            + Add Question
                        </button>
                    </div>
                    <div id="faq-questions-list">
                        ${faqData.questions.map((q, index) => `
                            <div class="faq-question-item" style="border: 1px solid #ddd; padding: 10px; margin-bottom: 10px; border-radius: 4px;">
                                <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px;">
                                    <strong>Question ${index + 1}</strong>
                                    <button type="button" onclick="removeFaqQuestion(${index})" style="background: #dc3545; color: white; border: none; padding: 4px 8px; border-radius: 3px; cursor: pointer; font-size: 12px;">Remove</button>
                                </div>
                                <div class="form-group">
                                    <label>Question:</label>
                                    <input type="text" value="${q.question}" onchange="updateFaqQuestion(${index}, 'question', this.value)" style="width: 100%; padding: 6px; border: 1px solid #ddd; border-radius: 3px;">
                                </div>
                                <div class="form-group">
                                    <label>Answer:</label>
                                    <textarea onchange="updateFaqQuestion(${index}, 'answer', this.value)" style="width: 100%; padding: 6px; border: 1px solid #ddd; border-radius: 3px; min-height: 60px; resize: vertical;">${q.answer}</textarea>
                                </div>
                            </div>
                        `).join('')}
                    </div>
                    
                    <h4 style="margin: 20px 0 10px 0; color: #333;">Styling Options</h4>
                    <div class="form-group">
                        <label>Question Background Color</label>
                        <input type="color" value="${faqData.questionBackgroundColor}" onchange="updateFaqStyle('questionBackgroundColor', this.value)">
                    </div>
                    <div class="form-group">
                        <label>Question Text Color</label>
                        <input type="color" value="${faqData.questionTextColor}" onchange="updateFaqStyle('questionTextColor', this.value)">
                    </div>
                    <div class="form-group">
                        <label>Answer Background Color</label>
                        <input type="color" value="${faqData.answerBackgroundColor}" onchange="updateFaqStyle('answerBackgroundColor', this.value)">
                    </div>
                    <div class="form-group">
                        <label>Answer Text Color</label>
                        <input type="color" value="${faqData.answerTextColor}" onchange="updateFaqStyle('answerTextColor', this.value)">
                    </div>
                    <div class="form-group">
                        <label>Icon Color</label>
                        <input type="color" value="${faqData.iconColor}" onchange="updateFaqStyle('iconColor', this.value)">
                    </div>
                    <div class="form-group">
                        <label>Border Radius</label>
                        <input type="text" value="${faqData.borderRadius}" onchange="updateFaqStyle('borderRadius', this.value)" placeholder="e.g. 8px">
                    </div>
                    <div class="form-group">
                        <label>Spacing Between Items</label>
                        <input type="text" value="${faqData.spacing}" onchange="updateFaqStyle('spacing', this.value)" placeholder="e.g. 10px">
                    </div>
                `;
            break;

            case 'simple-comments':
                const simpleCommentsData = content._simpleCommentsData || {
                    title: 'Comments',
                    showTitle: true,
                    allowAnonymous: true,
                    moderationEnabled: false,
                    requireEmail: true,
                    maxComments: 100,
                    sortOrder: 'newest',
                    backgroundColor: '#ffffff',
                    borderColor: '#e0e0e0',
                    textColor: '#333333',
                    buttonColor: '#007bff'
                };
                
                specificControls = `
                    <div class="form-group">
                        <label>Background Color</label>
                        <input type="color" value="${rgbToHex(content.style.backgroundColor || '#ffffff')}" onchange="updateStyle(this, 'backgroundColor')">
                        <small class="text-muted">Background behind the comments section</small>
                    </div>
                    
                    <h4 style="margin: 20px 0 10px 0; color: #333;">
                        <i class="fas fa-comment-dots" style="margin-right: 8px; color: #007bff;"></i>
                        Simple Comments Settings
                    </h4>
                    
                    <div class="alert alert-info" style="margin-bottom: 16px; padding: 12px; background: #e3f2fd; border: 1px solid #2196f3; border-radius: 6px;">
                        <i class="fas fa-info-circle" style="margin-right: 6px; color: #1976d2;"></i>
                        <strong>No Setup Required!</strong> Comments are stored in your database and work immediately.
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">
                            <i class="fas fa-heading" style="margin-right: 6px;"></i>
                            Comments Section Title
                        </label>
                        <input type="text" value="${simpleCommentsData.title}" 
                               onchange="updateSimpleCommentsField('title', this.value)" 
                               style="width: 100%; padding: 8px; border: 1px solid #ddd; border-radius: 4px;">
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333; display: flex; align-items: center;">
                            <input type="checkbox" ${simpleCommentsData.showTitle ? 'checked' : ''} 
                                   onchange="updateSimpleCommentsField('showTitle', this.checked)"
                                   style="margin-right: 8px;">
                            <i class="fas fa-eye" style="margin-right: 6px;"></i>
                            Show section title
                        </label>
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333; display: flex; align-items: center;">
                            <input type="checkbox" ${simpleCommentsData.allowAnonymous ? 'checked' : ''} 
                                   onchange="updateSimpleCommentsField('allowAnonymous', this.checked)"
                                   style="margin-right: 8px;">
                            <i class="fas fa-user-secret" style="margin-right: 6px;"></i>
                            Allow anonymous comments
                        </label>
                        <small style="color: #666; font-size: 12px; display: block; margin-top: 4px; margin-left: 24px;">
                            Users can comment without creating an account
                        </small>
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333; display: flex; align-items: center;">
                            <input type="checkbox" ${simpleCommentsData.requireEmail ? 'checked' : ''} 
                                   onchange="updateSimpleCommentsField('requireEmail', this.checked)"
                                   style="margin-right: 8px;">
                            <i class="fas fa-envelope" style="margin-right: 6px;"></i>
                            Require email address
                        </label>
                        <small style="color: #666; font-size: 12px; display: block; margin-top: 4px; margin-left: 24px;">
                            Email is required for posting comments
                        </small>
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333; display: flex; align-items: center;">
                            <input type="checkbox" ${simpleCommentsData.moderationEnabled ? 'checked' : ''} 
                                   onchange="updateSimpleCommentsField('moderationEnabled', this.checked)"
                                   style="margin-right: 8px;">
                            <i class="fas fa-shield-alt" style="margin-right: 6px;"></i>
                            Enable comment moderation
                        </label>
                        <small style="color: #666; font-size: 12px; display: block; margin-top: 4px; margin-left: 24px;">
                            Comments need approval before appearing
                        </small>
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">
                            <i class="fas fa-sort" style="margin-right: 6px;"></i>
                            Comment Sort Order
                        </label>
                        <select onchange="updateSimpleCommentsField('sortOrder', this.value)" 
                                style="width: 100%; padding: 8px; border: 1px solid #ddd; border-radius: 4px;">
                            <option value="newest" ${simpleCommentsData.sortOrder === 'newest' ? 'selected' : ''}>Newest First</option>
                            <option value="oldest" ${simpleCommentsData.sortOrder === 'oldest' ? 'selected' : ''}>Oldest First</option>
                        </select>
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">
                            <i class="fas fa-list-ol" style="margin-right: 6px;"></i>
                            Maximum Comments to Show
                        </label>
                        <input type="number" value="${simpleCommentsData.maxComments}" min="10" max="1000"
                               onchange="updateSimpleCommentsField('maxComments', parseInt(this.value))" 
                               style="width: 100%; padding: 8px; border: 1px solid #ddd; border-radius: 4px;">
                        <small style="color: #666; font-size: 12px; display: block; margin-top: 4px;">
                            Older comments will be paginated
                        </small>
                    </div>
                    
                    <h5 style="margin: 20px 0 10px 0; color: #333;">Styling Options</h5>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">Background Color</label>
                        <input type="color" value="${simpleCommentsData.backgroundColor}" 
                               onchange="updateSimpleCommentsField('backgroundColor', this.value)"
                               style="width: 100%; padding: 4px; border: 1px solid #ddd; border-radius: 4px;">
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">Border Color</label>
                        <input type="color" value="${simpleCommentsData.borderColor}" 
                               onchange="updateSimpleCommentsField('borderColor', this.value)"
                               style="width: 100%; padding: 4px; border: 1px solid #ddd; border-radius: 4px;">
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">Text Color</label>
                        <input type="color" value="${simpleCommentsData.textColor}" 
                               onchange="updateSimpleCommentsField('textColor', this.value)"
                               style="width: 100%; padding: 4px; border: 1px solid #ddd; border-radius: 4px;">
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">Button Color</label>
                        <input type="color" value="${simpleCommentsData.buttonColor}" 
                               onchange="updateSimpleCommentsField('buttonColor', this.value)"
                               style="width: 100%; padding: 4px; border: 1px solid #ddd; border-radius: 4px;">
                    </div>
                `;
            break;

            case 'disqus':
                const disqusData = content._disqusData || {
                    shortname: '',
                    identifier: '',
                    title: '',
                    url: '',
                    showInPreview: true
                };
                
                specificControls = `
                    <div class="form-group">
                        <label>Background Color</label>
                        <input type="color" value="${rgbToHex(content.style.backgroundColor || '#ffffff')}" onchange="updateStyle(this, 'backgroundColor')">
                        <small class="text-muted">Background behind the Disqus comments</small>
                    </div>
                    
                    <h4 style="margin: 20px 0 10px 0; color: #333;">
                        <i class="fas fa-comments" style="margin-right: 8px; color: #2e9fff;"></i>
                        Disqus Comments Configuration
                    </h4>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">
                            <i class="fas fa-cog" style="margin-right: 6px;"></i>
                            Disqus Shortname <span style="color: #dc3545;">*</span>
                        </label>
                        <input type="text" value="${disqusData.shortname}" 
                               onchange="updateDisqusField('shortname', this.value)" 
                               placeholder="your-site-shortname"
                               style="width: 100%; padding: 8px; border: 1px solid #ddd; border-radius: 4px; font-family: monospace;">
                        <small style="color: #666; font-size: 12px; display: block; margin-top: 4px;">
                            <i class="fas fa-info-circle" style="margin-right: 4px;"></i>
                            Find your shortname in Disqus Admin → Settings → General
                        </small>
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">
                            <i class="fas fa-fingerprint" style="margin-right: 6px;"></i>
                            Page Identifier (Optional)
                        </label>
                        <input type="text" value="${disqusData.identifier}" 
                               onchange="updateDisqusField('identifier', this.value)" 
                               placeholder="unique-page-id"
                               style="width: 100%; padding: 8px; border: 1px solid #ddd; border-radius: 4px;">
                        <small style="color: #666; font-size: 12px; display: block; margin-top: 4px;">
                            Unique identifier for this page. Leave empty to use the page URL.
                        </small>
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">
                            <i class="fas fa-heading" style="margin-right: 6px;"></i>
                            Discussion Title (Optional)
                        </label>
                        <input type="text" value="${disqusData.title}" 
                               onchange="updateDisqusField('title', this.value)" 
                               placeholder="Custom discussion title"
                               style="width: 100%; padding: 8px; border: 1px solid #ddd; border-radius: 4px;">
                        <small style="color: #666; font-size: 12px; display: block; margin-top: 4px;">
                            Custom title for the discussion. Leave empty to use the page title.
                        </small>
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333;">
                            <i class="fas fa-link" style="margin-right: 6px;"></i>
                            Canonical URL (Optional)
                        </label>
                        <input type="url" value="${disqusData.url}" 
                               onchange="updateDisqusField('url', this.value)" 
                               placeholder="https://example.com/page"
                               style="width: 100%; padding: 8px; border: 1px solid #ddd; border-radius: 4px;">
                        <small style="color: #666; font-size: 12px; display: block; margin-top: 4px;">
                            Canonical URL for this page. Leave empty to use the current page URL.
                        </small>
                    </div>
                    
                    <div class="form-group">
                        <label style="font-weight: 600; color: #333; display: flex; align-items: center;">
                            <input type="checkbox" ${disqusData.showInPreview ? 'checked' : ''} 
                                   onchange="updateDisqusField('showInPreview', this.checked)"
                                   style="margin-right: 8px;">
                            <i class="fas fa-eye" style="margin-right: 6px;"></i>
                            Show preview in page builder
                        </label>
                        <small style="color: #666; font-size: 12px; display: block; margin-top: 4px; margin-left: 24px;">
                            Display a preview box in the page builder. Uncheck to show only a minimal placeholder.
                        </small>
                    </div>
                    
                    <div style="
                        background: #e3f2fd; 
                        border: 1px solid #2196f3; 
                        border-radius: 6px; 
                        padding: 12px; 
                        margin: 16px 0;
                        font-size: 13px;
                    ">
                        <div style="display: flex; align-items: flex-start;">
                            <i class="fas fa-lightbulb" style="color: #2196f3; margin-right: 8px; margin-top: 2px;"></i>
                            <div>
                                <strong style="color: #1976d2;">Setup Required:</strong><br>
                                Make sure you have a Disqus account and have registered your website at 
                                <a href="https://disqus.com/admin/" target="_blank" style="color: #1976d2;">disqus.com/admin</a>
                            </div>
                        </div>
                    </div>
                `;
            break;

            case 'display-assets':
            specificControls = `
                <div class="form-group">
                <label>Add Files</label>
                <button onclick="openFileManager()">Manage Files</button>
                </div>
            `;
            break;

            case 'cards':
            specificControls = `
                <div class="form-group">
                <label>Manage Cards</label>
                <button onclick="openCardEditor()">Edit Cards</button>
                </div>
            `;
            break;

            case 'full-width-text-image':
                const fwti = content._fwtiData || {};
                specificControls = `
                    <div class="form-group">
                        <label>Background Color</label>
                        <input type="color" value="${rgbToHex(content.style.backgroundColor || '#ffffff')}" onchange="updateStyle(this, 'backgroundColor')">
                        <small class="text-muted">Background behind the full-width text and image</small>
                    </div>
                    <div class="form-group">
                        <label>Title Text</label>
                        <input type="text" value="${fwti.text1 || ''}" onchange="updateFWTIField(this.value, 'text1')">
                    </div>
                    <div class="form-group">
                        <label>Title Font Size</label>
                        <input type="text" value="${fwti.fontSize1 || '32px'}" onchange="updateFWTIField(this.value, 'fontSize1')">
                    </div>
                    <div class="form-group">
                        <label>Title Color</label>
                        <input type="color" value="${fwti.color1 || '#222222'}" onchange="updateFWTIField(this.value, 'color1')">
                    </div>
                    <div class="form-group">
                        <label>Subtitle Text</label>
                        <input type="text" value="${fwti.text2 || ''}" onchange="updateFWTIField(this.value, 'text2')">
                    </div>
                    <div class="form-group">
                        <label>Subtitle Font Size</label>
                        <input type="text" value="${fwti.fontSize2 || '18px'}" onchange="updateFWTIField(this.value, 'fontSize2')">
                    </div>
                    <div class="form-group">
                        <label>Subtitle Color</label>
                        <input type="color" value="${fwti.color2 || '#444444'}" onchange="updateFWTIField(this.value, 'color2')">
                    </div>
                    <div class="form-group">
                        <label>Image</label>
