                            <option value="grayscale(1)" ${pressData.logoOverlay === 'grayscale(1)' ? 'selected' : ''}>Grayscale</option>
                            <option value="opacity(0.7)" ${pressData.logoOverlay === 'opacity(0.7)' ? 'selected' : ''}>Semi-transparent</option>
