//  helper function for mergin

function updateStyleWithUnit(input, property) {
    if (!selectedComponent) return;
    // Always use px for margin fields
    selectedComponent.style[property] = input.value + 'px';
    // Update the input to reflect the actual value (removes any non-numeric input)
    setTimeout(() => {
        input.value = parseInt(selectedComponent.style[property]) || 0;
    }, 0);
}


// slider IMAGE UPLOAD & COLUMN UPDATE HELPERS

function uploadSliderImages(event) {
    if (!selectedComponent) return;
    const files = Array.from(event.target.files);
    if (!files.length) return;
    const content = getContentElement(selectedComponent);
    if (!content._sliderData) return;
    
    let loaded = 0;
    let errors = 0;
    const maxSize = 2 * 1024 * 1024; // 2MB per image
    
    files.forEach(file => {
        // Validate file type
        if (!file.type.startsWith('image/')) {
            showUploadNotification(`File "${file.name}" is not a valid image.`, 'error');
            errors++;
            return;
        }
        
        // Validate file size
        if (file.size > maxSize) {
            showUploadNotification(`File "${file.name}" (${(file.size / 1024 / 1024).toFixed(2)}MB) exceeds maximum size of 2MB.`, 'error');
            errors++;
            return;
        }
        
        {
            const reader = new FileReader();
            reader.onload = function(e) {
                content._sliderData.images.push(e.target.result);
                loaded++;
                if (loaded === files.length - errors) {
                    content.renderSlider();
                    updatePropertyPanel();
                    if (loaded > 0) {
                        showUploadNotification(`${loaded} image(s) uploaded successfully!`, 'success');
                    }
                }
            };
            reader.onerror = function() {
                showUploadNotification(`Failed to read file "${file.name}".`, 'error');
                errors++;
            };
            reader.readAsDataURL(file);
        }
    });
}

function updateSliderSlidesToShow(val) {
    if (!selectedComponent) return;
    const content = getContentElement(selectedComponent);
    if (!content._sliderData) return;
    // Update the slidesToShow value in the slider data
    content._sliderData.slidesToShow = Math.max(1, Math.min(10, parseInt(val, 10) || 1));
    content._sliderStartIdx = 0; // Reset to first slide
    // Re-render the slider with the new slidesToShow value
    content.renderSlider();
    // Don't update property panel immediately to avoid disrupting user input
    // updatePropertyPanel();
}

function updateSliderSlideSpeed(val) {
    if (!selectedComponent) return;
    const content = getContentElement(selectedComponent);
    if (!content._sliderData) return;
    content._sliderData.slideSpeed = Math.max(500, Math.min(10000, parseInt(val, 10) || 2000));
    content.renderSlider();
    // Don't update property panel immediately to avoid disrupting user input
    // updatePropertyPanel();
}

function updateSliderMarqueeMode(val) {
    if (!selectedComponent) return;
    const content = getContentElement(selectedComponent);
    if (!content._sliderData) return;
    content._sliderData.isMarquee = val === 'true';
    content.renderSlider();
    updatePropertyPanel();
}

// Debounced versions for real-time input without disrupting typing
let sliderSlidesToShowTimeout;
let sliderSlideSpeedTimeout;

function debouncedUpdateSliderSlidesToShow(val) {
    if (!selectedComponent) return;
    const content = getContentElement(selectedComponent);
    if (!content._sliderData) return;
    
    // Update the value immediately for responsiveness
    content._sliderData.slidesToShow = Math.max(1, Math.min(10, parseInt(val, 10) || 1));
    content._sliderStartIdx = 0;
    content.renderSlider();
    
    // Clear existing timeout
    clearTimeout(sliderSlidesToShowTimeout);
    
    // Set new timeout to avoid frequent panel updates
    sliderSlidesToShowTimeout = setTimeout(() => {
        // Only update panel if input is not actively focused
        const activeElement = document.activeElement;
        if (!activeElement || activeElement.tagName !== 'INPUT') {
            updatePropertyPanel();
        }
    }, 1000);
}

function debouncedUpdateSliderSlideSpeed(val) {
    if (!selectedComponent) return;
    const content = getContentElement(selectedComponent);
    if (!content._sliderData) return;
    
    // Update the value immediately for responsiveness
    content._sliderData.slideSpeed = Math.max(500, Math.min(10000, parseInt(val, 10) || 2000));
    content.renderSlider();
    
    // Clear existing timeout
    clearTimeout(sliderSlideSpeedTimeout);
    
    // Set new timeout to avoid frequent panel updates
    sliderSlideSpeedTimeout = setTimeout(() => {
        // Only update panel if input is not actively focused
        const activeElement = document.activeElement;
        if (!activeElement || activeElement.tagName !== 'INPUT') {
            updatePropertyPanel();
        }
    }, 1000);
}

