// Handle video file upload
function handleVideoUpload(event) {
    const file = event.target.files[0];
    if (!file) return;
    
    if (!selectedComponent) {
        showUploadNotification('Please select a component first.', 'error');
        return;
    }
    
    // Validate file type
    const allowedTypes = ['video/mp4', 'video/webm', 'video/ogg'];
    if (!allowedTypes.includes(file.type)) {
        showUploadNotification('Please upload a valid video file (MP4, WebM, or OGG).', 'error');
        event.target.value = '';
        return;
    }
    
    // Validate file size (50MB max)
    const maxSize = 50 * 1024 * 1024; // 50MB in bytes
    if (file.size > maxSize) {
        showUploadNotification('File size must be less than 50MB.', 'error');
        event.target.value = '';
        return;
    }
    
    // Show progress
    const progressDiv = document.getElementById('uploadProgress');
    const progressBar = document.getElementById('uploadProgressBar');
    const statusText = document.getElementById('uploadStatus');
    
    progressDiv.style.display = 'block';
    progressBar.style.width = '0%';
    statusText.textContent = 'Uploading...';
    
    // Create form data
    const formData = new FormData();
    formData.append('video', file);
    formData.append('_token', document.querySelector('meta[name="csrf-token"]').content);
    
    // Upload using XMLHttpRequest for progress tracking
    const xhr = new XMLHttpRequest();
    
    xhr.upload.addEventListener('progress', function(e) {
        if (e.lengthComputable) {
            const percentComplete = (e.loaded / e.total) * 100;
            progressBar.style.width = percentComplete + '%';
            statusText.textContent = 'Uploading: ' + Math.round(percentComplete) + '%';
        }
    });
    
    xhr.addEventListener('load', function() {
        if (xhr.status === 200) {
            try {
                const response = JSON.parse(xhr.responseText);
                if (response.success && response.url) {
                    // Update video URL
                    updateVideoField(response.url, 'videoUrl');
                    
                    // Detect video type from filename
                    const extension = response.url.split('.').pop().toLowerCase();
                    if (['mp4', 'webm', 'ogg'].includes(extension)) {
                        updateVideoField(extension, 'videoType');
                    }
                    
                    // Update progress
                    progressBar.style.width = '100%';
                    progressBar.style.background = '#28a745';
                    statusText.textContent = 'Upload complete!';
                    statusText.style.color = '#28a745';
                    
                    // Update URL input
                    const urlInput = document.getElementById('videoUrlInput');
                    if (urlInput) {
                        urlInput.value = response.url;
                    }
                    
                    // Hide progress after 2 seconds
                    setTimeout(() => {
                        progressDiv.style.display = 'none';
                        progressBar.style.background = '#667eea';
                        statusText.style.color = '#666';
                    }, 2000);
                    
                } else {
                    throw new Error(response.message || 'Upload failed');
                }
            } catch (error) {
                progressBar.style.background = '#dc3545';
                statusText.textContent = 'Upload failed: ' + error.message;
                statusText.style.color = '#dc3545';
            }
        } else {
            progressBar.style.background = '#dc3545';
            statusText.textContent = 'Upload failed: Server error';
            statusText.style.color = '#dc3545';
        }
    });
    
    xhr.addEventListener('error', function() {
        progressBar.style.background = '#dc3545';
        statusText.textContent = 'Upload failed: Network error';
        statusText.style.color = '#dc3545';
    });
    
    xhr.open('POST', '/admins/upload-video');
    xhr.send(formData);
}

