function addPressCard() {
    if (!selectedComponent) return;
    
    const content = getContentElement(selectedComponent);
    if (!content._pressCardData) return;
    
    if (!content._pressCardData.cards) {
        content._pressCardData.cards = [];
    }
    
    const newCard = {
        logoSrc: '',
        logoAlt: 'Press Logo',
        title: 'New Press Article',
        url: '#',
        date: new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }),
        target: '_blank'
    };
    
    content._pressCardData.cards.push(newCard);
    
    // Refresh just the press card settings without losing selection
    if (selectedComponent && selectedComponent.classList.contains('selected')) {
        refreshPressCardSettings();
    }
    
    if (typeof content.renderPressCard === 'function') {
        content.renderPressCard();
    }
}

function removePressCard(index) {
    if (!selectedComponent) return;
    
    const content = getContentElement(selectedComponent);
    if (!content._pressCardData || !content._pressCardData.cards) return;
    
    if (content._pressCardData.cards.length > 1) {
        content._pressCardData.cards.splice(index, 1);
        
        // Refresh just the press card settings without losing selection
        refreshPressCardSettings();
        
        if (typeof content.renderPressCard === 'function') {
            content.renderPressCard();
        }
    } else {
        alert('You must have at least one card.');
    }
}

function uploadPressCardImage(input, cardIndex) {
    if (!selectedComponent) return;
    const file = input.files[0];
    if (!file) return;
    
    // Validate file type
    if (!file.type.startsWith('image/')) {
        showUploadNotification('Please select a valid image file.', 'error');
        input.value = '';
        return;
    }
    
    // Validate file size (1MB max for press cards)
    const maxSize = 1 * 1024 * 1024;
    if (file.size > maxSize) {
        showUploadNotification(`File size exceeds the maximum allowed size of 1MB.`, 'error');
        input.value = '';
        return;
    }
    
    {
        const reader = new FileReader();
        reader.onload = function(e) {
            updatePressCardField(`cards.${cardIndex}.logoSrc`, e.target.result);
            // Update the property panel to show the new image without losing selection
            refreshPressCardSettings();
            showUploadNotification('Logo image uploaded successfully!', 'success');
        };
        reader.onerror = function() {
            showUploadNotification('Failed to read the image file.', 'error');
            input.value = '';
        };
        reader.readAsDataURL(file);
    }
}

