                        <label>Question</label>
                        <input type="text" class="form-control" name="faq_question_${'${i}'}" value="">
                    </div>
                    <div class="form-group">
                        <label>Answer</label>
                        <textarea class="form-control text-editor" name="faq_answer_${'${i}'}" rows="3"></textarea>
