                          buttonDefaults.buttonPadding = compData.properties.button_padding || buttonDefaults.buttonPadding;
                          buttonDefaults.borderRadius = compData.properties.border_radius || buttonDefaults.borderRadius;
                          buttonDefaults.fontSize = compData.properties.font_size || buttonDefaults.fontSize;
                          buttonDefaults.fontWeight = compData.properties.font_weight || buttonDefaults.fontWeight;
                          buttonDefaults.textAlign = compData.properties.text_align || buttonDefaults.textAlign;
                          buttonDefaults.textDecoration = compData.properties.text_decoration || buttonDefaults.textDecoration;
                          buttonDefaults.border = compData.properties.border || buttonDefaults.border;
                          buttonDefaults.boxShadow = compData.properties.box_shadow || buttonDefaults.boxShadow;
                          buttonDefaults.transition = compData.properties.transition || buttonDefaults.transition;
                        }
                        
                        nestedContent._buttonData = compData.buttonData || buttonDefaults;
                        nestedContent.renderButton();
                        break;
                      case 'invest-cta':
                        if (compData.investCtaData && Object.keys(compData.investCtaData).length > 0) {
                          nestedContent._investCtaData = compData.investCtaData;
                          console.log('Nested invest-cta deserialized with structured data:', compData.investCtaData);
                        } else if (compData.html) {
                          // Recovery: parse from HTML if structured data missing
                          try {
                            const tempDiv = document.createElement('div');
                            tempDiv.innerHTML = compData.html;
                            const btnText = tempDiv.querySelector('.cta-button')?.textContent || 'Invest Now';
                            const btnUrl = tempDiv.querySelector('.cta-button')?.getAttribute('href') || '#';
                            const leftValue = tempDiv.querySelector('.left-value')?.textContent || '0';
                            const leftLabel = tempDiv.querySelector('.left-label')?.textContent || 'Metric 1';
                            const rightValue = tempDiv.querySelector('.right-value')?.textContent || '0';
                            const rightLabel = tempDiv.querySelector('.right-label')?.textContent || 'Metric 2';
                            
                            nestedContent._investCtaData = {
                              buttonText: btnText,
                              buttonUrl: btnUrl,
                              leftValue: leftValue,
                              leftLabel: leftLabel,
                              rightValue: rightValue,
                              rightLabel: rightLabel,
                              backgroundColor: 'rgb(59, 130, 246)',
                              textColor: '#ffffff'
                            };
                            console.log('Recovered invest-cta from HTML:', nestedContent._investCtaData);
                          } catch (e) {
                            console.error('Failed to parse invest-cta from HTML:', e);
                            nestedContent._investCtaData = {
                              buttonText: 'Invest Now',
                              buttonUrl: '#',
                              leftValue: '0',
                              leftLabel: 'Metric 1',
                              rightValue: '0',
                              rightLabel: 'Metric 2',
                              backgroundColor: 'rgb(59, 130, 246)',
                              textColor: '#ffffff'
                            };
                          }
                        } else {
                          nestedContent._investCtaData = {
                            buttonText: 'Invest Now',
                            buttonUrl: '#',
                            leftValue: '0',
                            leftLabel: 'Metric 1',
                            rightValue: '0',
                            rightLabel: 'Metric 2',
                            backgroundColor: 'rgb(59, 130, 246)',
                            textColor: '#ffffff'
                          };
                        }
                        nestedContent.renderInvestCta();
                        break;
                      default:
                        // For basic components like text, heading, etc., just restore HTML
                        if (nestedContent && compData.html) {
                          nestedContent.innerHTML = compData.html;
                        }
                        break;
                    }
                    
                    // Restore styles (only if not already handled by component-specific rendering)
                    if (nestedContent && compData.style && !['image', 'gallery', 'slider', 'custom-form', 'event-countdown', 'event-information', 'site-goal', 'custom-banner', 'sell-tickets', 'full-width-text-image', 'press-card', 'video', 'investment-tier', 'statistics-metric', 'invest-cta', 'button'].includes(compData.type)) {
                      Object.assign(nestedContent.style, compData.style);
                    }
                    
                    // Restore wrapper styles
                    if (compData.wrapperStyle) {
                      Object.assign(nestedComponent.style, compData.wrapperStyle);
                    }
                    
                    // Restore responsive styles
                    if (compData.responsiveStyles) {
                      nestedContent._responsiveStyles = compData.responsiveStyles;
                    }
                    
                    // Add to column
                    console.log(`Before appending to column ${columnIndex}, columns[${columnIndex}] HTML:`, columns[columnIndex].outerHTML.substring(0, 100));
                    console.log(`Before appending, nestedComponent:`, nestedComponent);
                    columns[columnIndex].appendChild(nestedComponent);
                    console.log(`After appending nested ${compData.type} to column ${columnIndex}, children:`, columns[columnIndex].children.length);
                    
                    // Hide dropzone text
                    const dropzone = columns[columnIndex].querySelector('.column-dropzone');
                    if (dropzone) dropzone.style.display = 'none';
                  });
                }
              });
            }
            
            if (data.style) {
              Object.assign(content.style, data.style);
            }
            if (data.wrapperStyle) Object.assign(component.style, data.wrapperStyle);
            if (data.responsiveStyles) content._responsiveStyles = data.responsiveStyles;
            break;
          // ...add other types as needed...
          default:
            content.innerHTML = data.html;
            if (data.style) {
              Object.assign(content.style, data.style);
            }
            if (data.wrapperStyle) {
              Object.assign(component.style, data.wrapperStyle);
            }
            if (data.responsiveStyles) {
              content._responsiveStyles = data.responsiveStyles;
            }
          }
        }
        
        // Restore responsive styles for all component types (fallback)
        if (data.responsiveStyles) {
          content._responsiveStyles = data.responsiveStyles;
          console.log(`Fallback: Restored responsive styles for component ${idx}:`, content._responsiveStyles);
        } else {
          console.log(`No responsive styles to restore for component ${idx}`);
        }
        
        page.appendChild(component);
        console.log(`Component ${idx} final responsive styles:`, content._responsiveStyles);
        // Add dropzone after each component except the last
        if (idx < state.length - 1) {
          page.appendChild(createDropzone());
        }
      });
      // Always ensure a dropzone at the end
      page.appendChild(createDropzone());
      
      // Apply responsive CSS after all components are loaded
      setTimeout(() => {
        updateResponsiveCSS();
        
        // CRITICAL: Refresh all backgrounds after page load to ensure they appear in canvas
        const innerSections = document.querySelectorAll('.inner-section-component');
        innerSections.forEach(section => {
          const content = getContentElement(section);
          if (content && content.updateBackground && typeof content.updateBackground === 'function') {
            content.updateBackground();
            console.log('Refreshed background for section after full page load:', content._innerSectionData);
          }
        });
      }, 100);
    }

    function saveBuilderState() {
      console.log('=== SAVE BUILDER STATE CALLED ===');
      id = document.getElementById('page_id').value;
      console.log('Page ID:', id);

      // Show loading state
      const saveButton = document.querySelector('.save-btn');
      const originalText = saveButton.innerHTML;
      saveButton.innerHTML = '<i class="bi bi-arrow-clockwise" style="animation: spin 1s linear infinite;"></i> Saving...';
      saveButton.disabled = true;
      saveButton.style.opacity = '0.7';

      const state = serializeBuilder();
      console.log('Serialized state:', state);
      console.log('State components count:', state.components ? state.components.length : 'no components');
      
      // Log what we're about to save - the ACTUAL inner-section data with buttons
      if (state.components && state.components.length > 0) {
        state.components.forEach((comp, idx) => {
          if (comp.type === 'inner-section' && comp.nestedComponents) {
            console.log(`=== ABOUT TO SAVE: Component ${idx} (inner-section) ===`);
            console.log(`nestedComponents length: ${comp.nestedComponents.length}`);
            comp.nestedComponents.forEach((col, colIdx) => {
              console.log(`  Column ${colIdx}: ${col.length} components`);
              col.forEach((nested, nestedIdx) => {
                console.log(`    Nested ${nestedIdx}: type=${nested.type}`);
              });
            });
            console.log(`=== END SAVE DATA FOR COMPONENT ${idx} ===`);
          }
        });
      }
      
      // Log press card data specifically
      if (state.components) {
        state.components.forEach((comp, idx) => {
          if (comp.type === 'press-card' || (comp.nestedComponents && comp.nestedComponents.some(col => col.some(nested => nested.type === 'press-card')))) {
            console.log(`Component ${idx} has press card data:`, comp);
          }
        });
      }
      
      // Get show_in_menu value from checkbox
      const showInMenuCheckbox = document.getElementById('showInMenu');
      const showInMenu = showInMenuCheckbox ? (showInMenuCheckbox.checked ? 1 : 0) : 1;
      console.log('Show in menu value:', showInMenu);
      
      // Get enable_confetti value from checkbox
      const enableConfettiCheckbox = document.getElementById('enableConfetti');
      const enableConfetti = enableConfettiCheckbox ? (enableConfettiCheckbox.checked ? 1 : 0) : 0;
      console.log('Enable confetti value:', enableConfetti);
      
      // Get page background color - prefer window.pageData as authoritative source
      let backgroundColor = '#ffffff'; // fallback
      
      // 1. Try to get from pageData (in-memory state)
      if (window.pageData && window.pageData.background_color) {
        backgroundColor = window.pageData.background_color;
        console.log('[saveBuilderState] Got background from pageData:', backgroundColor);
      } else {
        // 2. Fallback to color input value
        const pageBackgroundColor = document.getElementById('pageBackgroundColor');
        if (pageBackgroundColor) {
          backgroundColor = pageBackgroundColor.value || '#ffffff';
          console.log('[saveBuilderState] Got background from input.value:', backgroundColor);
        }
      }
      
      console.log('[saveBuilderState] Final background color value:', backgroundColor);

      fetch('/admins/page/save/'+id, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'X-CSRF-TOKEN': document.querySelector('meta[name="csrf-token"]').getAttribute('content') },
        body: JSON.stringify({ 
          state: state,
          show_in_menu: showInMenu,
          enable_confetti: enableConfetti,
          background_color: backgroundColor
        })
      })
      .then(res => {
        console.log('Save response status:', res.status);
        return res.json();
      })
      .then(data => { 
        console.log('Save response data:', data);
        if (data.success !== false) {
          showSuccessNotification('Page Saved Successfully!', 'All your changes have been saved and are now live.');
        } else {
          showErrorNotification('Save Failed', data.message || 'An error occurred while saving the page.');
        }
      })
      .catch(error => {
        console.error('Save failed:', error);
        showErrorNotification('Save Failed', 'Unable to save the page. Please check your connection and try again.');
      })
      .finally(() => {
        // Restore button state
        saveButton.innerHTML = originalText;
        saveButton.disabled = false;
        saveButton.style.opacity = '1';
      });
      
      console.log('=== END SAVE BUILDER STATE ===');
    }

    // Template Functions
    function showSaveAsTemplateModal() {
      const modal = document.getElementById('saveAsTemplateModal');
      modal.style.display = 'flex';
      
      // Set default template name based on page name if available
      const pageNameInput = document.querySelector('[name="name"]');
      const templateNameInput = document.getElementById('templateName');
      if (pageNameInput && pageNameInput.value) {
        templateNameInput.value = pageNameInput.value + ' Template';
      }
    }

    function closeSaveAsTemplateModal() {
      const modal = document.getElementById('saveAsTemplateModal');
      modal.style.display = 'none';
      
      // Clear form
      document.getElementById('saveAsTemplateForm').reset();
    }

    function savePageAsTemplate() {
      const pageId = document.getElementById('page_id').value;
      const templateName = document.getElementById('templateName').value.trim();
      const templateDescription = document.getElementById('templateDescription').value.trim();
      const templateCategory = document.getElementById('templateCategory').value;
      const isPublic = document.getElementById('templateIsPublic').checked;

      if (!templateName) {
        showWarningNotification('Template Name Required', 'Please enter a name for your template before saving.');
        return;
      }

      // Get current page state
      const currentState = serializeBuilder();
      
      const formData = new FormData();
      formData.append('template_name', templateName);
      formData.append('template_description', templateDescription);
      formData.append('template_category', templateCategory);
      if (isPublic) {
        formData.append('is_public', '1');
      }

      fetch(`/admins/templates/save-from-page/${pageId}`, {
        method: 'POST',
        headers: {
          'X-CSRF-TOKEN': document.querySelector('meta[name="csrf-token"]').getAttribute('content')
        },
        body: formData
      })
      .then(response => response.json())
      .then(data => {
        if (data.success) {
          showSuccessNotification('Template Saved!', data.message || 'Your page has been successfully saved as a template.');
          closeSaveAsTemplateModal();
          
          // Ask if user wants to view templates
          setTimeout(() => {
            const viewTemplates = confirm('Would you like to view the templates page?');
            if (viewTemplates) {
              window.open('/admins/templates', '_blank');
            }
          }, 1000);
        } else {
          showErrorNotification('Template Save Failed', data.message || 'An error occurred while saving the template.');
        }
      })
      .catch(error => {
        console.error('Error:', error);
        showErrorNotification('Template Save Failed', 'Unable to save template. Please check your connection and try again.');
      });
    }

    // Close modal when clicking outside of it
    document.addEventListener('click', function(event) {
      const modal = document.getElementById('saveAsTemplateModal');
      if (event.target === modal) {
        closeSaveAsTemplateModal();
      }
    });

    // Close modal with Escape key
    document.addEventListener('keydown', function(event) {
      if (event.key === 'Escape') {
        const saveModal = document.getElementById('saveAsTemplateModal');
        const applyModal = document.getElementById('applyTemplateModal');
        if (saveModal.style.display === 'flex') {
          closeSaveAsTemplateModal();
        }
        if (applyModal.style.display === 'flex') {
          closeApplyTemplateModal();
        }
      }
    });

    // Apply Template Functions
    let selectedTemplateId = null;

    function showApplyTemplateModal() {
      const modal = document.getElementById('applyTemplateModal');
      modal.style.display = 'flex';
      loadTemplatesForApply();
    }

    function closeApplyTemplateModal() {
      const modal = document.getElementById('applyTemplateModal');
      modal.style.display = 'none';
      selectedTemplateId = null;
      
      // Reset apply button
      const applyBtn = document.getElementById('applyTemplateBtn');
      applyBtn.disabled = true;
      applyBtn.style.opacity = '0.5';
      
      // Hide warning
      document.getElementById('applyWarning').style.display = 'none';
    }

    function loadTemplatesForApply() {
      const category = document.getElementById('templateCategoryFilter').value;
      const container = document.getElementById('templatesContainer');
      
      container.innerHTML = '<p style="text-align:center; color:#666;">Loading templates...</p>';
      
      fetch(`/admins/templates/get-templates?category=${category}`)
      .then(response => response.json())
      .then(templates => {
        if (templates.length === 0) {
          container.innerHTML = '<p style="text-align:center; color:#999;">No templates found in this category.</p>';
          return;
        }
        
        let html = '<div style="display:grid; gap:10px;">';
        templates.forEach(template => {
          html += `
            <div class="template-card" onclick="selectTemplateForApply(${template.id}, '${template.name}')" 
                 style="border:1px solid #ddd; border-radius:5px; padding:15px; cursor:pointer; transition:all 0.2s;
                        background:#f8f9fa;" 
                 onmouseover="this.style.borderColor='#17a2b8'; this.style.background='#e3f2fd';"
                 onmouseout="this.style.borderColor='#ddd'; this.style.background='#f8f9fa';">
              <div style="display:flex; justify-content:between; align-items:start;">
                <div style="flex:1;">
                  <h6 style="margin:0 0 5px 0; color:#333; font-weight:bold;">${template.name}</h6>
                  <p style="margin:0 0 8px 0; color:#666; font-size:13px; line-height:1.4;">
                    ${template.description || 'No description provided'}
                  </p>
                  <div style="display:flex; gap:10px; align-items:center;">
                    <span style="background:#17a2b8; color:white; padding:3px 8px; border-radius:3px; font-size:11px;">
                      ${template.category ? template.category.charAt(0).toUpperCase() + template.category.slice(1) : 'General'}
                    </span>
                    <small style="color:#999;">
                      <i class="bi bi-download" style="margin-right:3px;"></i>Used ${template.usage_count} times
                    </small>
                  </div>
                </div>
              </div>
            </div>
          `;
        });
        html += '</div>';
        
        container.innerHTML = html;
      })
      .catch(error => {
        console.error('Error:', error);
        container.innerHTML = '<p style="text-align:center; color:#dc3545;">Error loading templates.</p>';
      });
    }

    function selectTemplateForApply(templateId, templateName) {
      // Remove previous selection
      document.querySelectorAll('.template-card').forEach(card => {
        card.style.borderColor = '#ddd';
        card.style.background = '#f8f9fa';
        card.style.borderWidth = '1px';
      });
      
      // Highlight selected template
      event.currentTarget.style.borderColor = '#28a745';
      event.currentTarget.style.borderWidth = '2px';
      event.currentTarget.style.background = '#d4edda';
      
      selectedTemplateId = templateId;
      
      // Enable apply button
      const applyBtn = document.getElementById('applyTemplateBtn');
      applyBtn.disabled = false;
      applyBtn.style.opacity = '1';
      
      // Show warning
      document.getElementById('applyWarning').style.display = 'block';
    }

    function applySelectedTemplate() {
      if (!selectedTemplateId) {
        alert('Please select a template first');
        return;
      }
      
      if (!confirm('⚠️ Are you sure you want to apply this template? This will replace ALL current page content and cannot be undone.')) {
        return;
      }
      
      const pageId = document.getElementById('page_id').value;
      
      fetch(`/admins/templates/apply-to-page/${selectedTemplateId}/${pageId}`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-CSRF-TOKEN': document.querySelector('meta[name="csrf-token"]').getAttribute('content')
        }
      })
      .then(response => response.json())
      .then(data => {
        if (data.success) {
          alert('✅ ' + data.message);
          closeApplyTemplateModal();
          
          // Reload page to show applied template content
          window.location.reload();
        } else {
          alert('❌ Error applying template: ' + (data.message || 'Unknown error'));
        }
      })
      .catch(error => {
        console.error('Error:', error);
        alert('❌ Error applying template: ' + error.message);
      });
    }

    // Section Template Functions
    let currentSectionComponent = null;
    let selectedSectionTemplateId = null;

    function saveSectionAsTemplate(btn, event) {
      event.preventDefault();
      event.stopPropagation();
      
      // Get the component element
      currentSectionComponent = btn.closest('.component');
      
      if (!currentSectionComponent || currentSectionComponent.dataset.type !== 'inner-section') {
        showErrorNotification('Invalid Section', 'Please select a valid inner-section to save as template.');
        return;
      }
      
      // Show modal
      const modal = document.getElementById('saveSectionTemplateModal');
      modal.style.display = 'flex';
      
      // Set default template name
      const sectionData = currentSectionComponent.querySelector('.inner-section-component')._innerSectionData;
      const columns = sectionData.columns || 2;
      document.getElementById('sectionTemplateName').value = `${columns} Column Section`;
    }

    function closeSaveSectionTemplateModal() {
      const modal = document.getElementById('saveSectionTemplateModal');
      modal.style.display = 'none';
      currentSectionComponent = null;
      document.getElementById('saveSectionTemplateForm').reset();
    }

    function saveSectionTemplateConfirm() {
      const templateName = document.getElementById('sectionTemplateName').value.trim();
      const templateDescription = document.getElementById('sectionTemplateDescription').value.trim();
      const templateCategory = document.getElementById('sectionTemplateCategory').value;
      const isPublic = document.getElementById('sectionTemplateIsPublic').checked;

      if (!templateName) {
        showWarningNotification('Template Name Required', 'Please enter a name for your section template.');
        return;
      }

      if (!currentSectionComponent) {
        showErrorNotification('No Section Selected', 'Please select a section to save as template.');
        return;
      }

      // Extract section data
      const content = currentSectionComponent.querySelector('.inner-section-component');
      const sectionData = {
        componentType: 'inner-section',
        innerSectionData: content._innerSectionData || {},
        nestedComponents: []
      };

      // Extract nested components from columns
      const columns = content.querySelectorAll('.inner-column');
      columns.forEach((column, columnIndex) => {
        sectionData.nestedComponents[columnIndex] = [];
        
        const components = column.querySelectorAll('.component');
        components.forEach(comp => {
          const compData = extractComponentData(comp);
          if (compData) {
            sectionData.nestedComponents[columnIndex].push(compData);
          }
        });
      });

      // Save to backend
      const formData = new FormData();
      formData.append('template_name', templateName);
      formData.append('template_description', templateDescription);
      formData.append('template_category', templateCategory);
      formData.append('template_data', JSON.stringify(sectionData));
      if (isPublic) {
        formData.append('is_public', '1');
      }

      fetch('/admins/section-templates/save', {
        method: 'POST',
        headers: {
          'X-CSRF-TOKEN': document.querySelector('meta[name="csrf-token"]').getAttribute('content')
        },
        body: formData
      })
      .then(response => response.json())
      .then(data => {
        if (data.success) {
          showSuccessNotification('Section Template Saved!', data.message || 'Your section has been successfully saved as a template.');
          closeSaveSectionTemplateModal();
        } else {
          showErrorNotification('Save Failed', data.message || 'An error occurred while saving the section template.');
        }
      })
      .catch(error => {
        console.error('Error:', error);
        showErrorNotification('Save Failed', 'Unable to save section template. Please check your connection and try again.');
      });
    }

    // Helper function to extract component data
    function extractComponentData(component) {
      const type = component.dataset.type;
      const content = component.querySelector('.component-content') || 
                      component.querySelector('.inner-section-component') ||
                      component.querySelector('[class*="-preview"]') ||
                      component.querySelector('[class*="-component"]');
      
      if (!content && type !== 'inner-section') return null;

      let componentData = {
        type: type,
        componentType: type
      };

      // Save common styles
      if (content && content.style) {
        componentData.style = {
          color: content.style.color || '',
          backgroundColor: content.style.backgroundColor || '',
          fontSize: content.style.fontSize || '',
          padding: content.style.padding || '',
          textAlign: content.style.textAlign || '',
          border: content.style.border || '',
          borderRadius: content.style.borderRadius || '',
          margin: content.style.margin || '',
        };
      }

      // Extract data based on component type - matching serializeBuilder logic
      switch(type) {
        case 'inner-section':
          const innerContent = component.querySelector('.inner-section-component');
          if (innerContent && innerContent._innerSectionData) {
            componentData.innerSectionData = innerContent._innerSectionData;
            componentData.nestedComponents = [];
            
            const columns = innerContent.querySelectorAll('.inner-column');
            columns.forEach((column, columnIndex) => {
              componentData.nestedComponents[columnIndex] = [];
              const nestedComps = column.querySelectorAll(':scope > .component');
              nestedComps.forEach(nested => {
                const nestedData = extractComponentData(nested);
                if (nestedData) {
                  componentData.nestedComponents[columnIndex].push(nestedData);
                }
              });
            });
          }
          break;
        
        case 'video-background':
          if (content._videoData) {
            componentData.videoData = content._videoData;
          }
          break;
        
        case 'slider':
          if (content._sliderData) {
            componentData.sliderData = content._sliderData;
          }
          break;
        
        case 'gallery':
          if (content._galleryData) {
            componentData.galleryData = content._galleryData;
          }
          break;
        
        case 'image':
          if (content._imageData) {
            componentData.imageData = content._imageData;
          }
          break;
        
        case 'invest-cta':
          if (content._investCtaData) {
            componentData.investCtaData = content._investCtaData;
          }
          break;
        
        case 'newsletter':
          if (content.newsletterData) {
            componentData.newsletterData = content.newsletterData;
          }
          break;
        
        case 'text-images':
          if (content._textImagesData) {
            componentData.textImagesData = content._textImagesData;
          }
          break;
        
        case 'feature-grid':
          if (content._featureGridData) {
            componentData.featureGridData = content._featureGridData;
          }
          break;
        
        case 'text':
          // Get text content from canvas preview element (NOT property panel editor)
          const textContentElement = content.querySelector('[id^="text-content-"]');
          if (textContentElement && textContentElement.innerHTML) {
            componentData.html = textContentElement.innerHTML;
            console.log('Text component serialized from canvas preview:', componentData.html);
          } else {
            // Fallback to content innerHTML
            componentData.html = content.innerHTML;
            console.log('Text component serialized from content innerHTML:', componentData.html);
          }
          break;
        
        case 'section-title':
          // Get section title content from canvas preview element
          const sectionTitleElement = content.querySelector('[id^="section-title-content-"]');
          if (sectionTitleElement && sectionTitleElement.innerHTML) {
            componentData.html = sectionTitleElement.innerHTML;
            console.log('Section title serialized from canvas preview:', componentData.html);
          } else {
            // Fallback to content innerHTML
            componentData.html = content.innerHTML;
            console.log('Section title serialized from content innerHTML:', componentData.html);
          }
          break;
        
        default:
          // For other components, try to get saved data
          if (content.innerHTML) {
            componentData.html = content.innerHTML;
          }
      }

      return componentData;
    }

    // Insert Section Template Functions
    function showInsertSectionTemplateModal() {
      targetInnerSectionComponent = null; // Clear target for global insert (add to canvas)
      const modal = document.getElementById('insertSectionTemplateModal');
      modal.style.display = 'flex';
      loadSectionTemplates();
    }

    function closeInsertSectionTemplateModal() {
      const modal = document.getElementById('insertSectionTemplateModal');
      modal.style.display = 'none';
      selectedSectionTemplateId = null;
      targetInnerSectionComponent = null; // Reset target
      
      // Reset insert button
      const insertBtn = document.getElementById('insertSectionBtn');
      if (insertBtn) {
        insertBtn.disabled = true;
        insertBtn.style.opacity = '0.5';
      }
    }

    function loadSectionTemplates() {
      const category = document.getElementById('sectionTemplateCategoryFilter').value;
      const container = document.getElementById('sectionTemplatesContainer');
      
      container.innerHTML = '<p style="text-align:center; color:#666;">Loading section templates...</p>';
      
      let url = '/admins/section-templates/list';
      if (category) {
        url += `?category=${category}`;
      }
      
      fetch(url)
        .then(response => response.json())
        .then(data => {
          if (data.success && data.templates && data.templates.length > 0) {
            container.innerHTML = '';
            
            data.templates.forEach(template => {
              const templateCard = document.createElement('div');
              templateCard.style.cssText = 'border:1px solid #ddd; border-radius:5px; padding:15px; margin-bottom:10px; cursor:pointer; transition:all 0.3s;';
              templateCard.onmouseover = function() { this.style.borderColor = '#6f42c1'; this.style.backgroundColor = '#f8f5ff'; };
              templateCard.onmouseout = function() { this.style.borderColor = '#ddd'; this.style.backgroundColor = 'white'; };
              templateCard.onclick = function() { selectSectionTemplate(template.id, templateCard); };
              
              templateCard.innerHTML = `
                <h5 style="margin:0 0 10px 0; color:#333;">${template.name}</h5>
                ${template.description ? `<p style="margin:0 0 10px 0; color:#666; font-size:13px;">${template.description}</p>` : ''}
                <div style="display:flex; justify-content:space-between; align-items:center;">
                  <span style="background:#6f42c1; color:white; padding:4px 8px; border-radius:4px; font-size:12px;">${template.category || 'general'}</span>
                  <span style="color:#999; font-size:12px;">Created: ${new Date(template.created_at).toLocaleDateString()}</span>
                </div>
              `;
              
              container.appendChild(templateCard);
            });
          } else {
            container.innerHTML = '<p style="text-align:center; color:#999; padding:20px;">No section templates found. Create your first section template by clicking "Save Template" on any inner-section!</p>';
          }
        })
        .catch(error => {
          console.error('Error loading section templates:', error);
          container.innerHTML = '<p style="text-align:center; color:#dc3545;">Error loading templates. Please try again.</p>';
        });
    }

    function selectSectionTemplate(templateId, cardElement) {
      selectedSectionTemplateId = templateId;
      
      // Remove selected class from all cards
      const cards = document.querySelectorAll('#sectionTemplatesContainer > div');
      cards.forEach(card => {
        card.style.borderColor = '#ddd';
        card.style.backgroundColor = 'white';
      });
      
      // Add selected class to this card
      cardElement.style.borderColor = '#6f42c1';
      cardElement.style.backgroundColor = '#f8f5ff';
      cardElement.style.borderWidth = '2px';
      
      // Enable insert button
      const insertBtn = document.getElementById('insertSectionBtn');
      if (insertBtn) {
        insertBtn.disabled = false;
        insertBtn.style.opacity = '1';
      }
    }

    // Insert section template into specific inner-section
    let targetInnerSectionComponent = null;

    function insertSectionToInnerSection(btn, event) {
      event.preventDefault();
      event.stopPropagation();
      
      // Get the target inner-section component
      targetInnerSectionComponent = btn.closest('.component');
      
      if (!targetInnerSectionComponent || targetInnerSectionComponent.dataset.type !== 'inner-section') {
        showErrorNotification('Invalid Section', 'Please select a valid inner-section.');
        return;
      }
      
      // Show the insert modal
      const modal = document.getElementById('insertSectionTemplateModal');
      modal.style.display = 'flex';
      loadSectionTemplates();
    }

    function insertSelectedSectionTemplate() {
      if (!selectedSectionTemplateId) {
        showWarningNotification('No Template Selected', 'Please select a section template to insert.');
        return;
      }
      
      fetch(`/admins/section-templates/get/${selectedSectionTemplateId}`)
        .then(response => response.json())
        .then(data => {
          if (data.success && data.template_data) {
            // Parse template data
            let templateData = data.template_data;
            if (typeof templateData === 'string') {
              templateData = JSON.parse(templateData);
            }
            
            // Create component from template data
            const newComponent = createComponentFromData(templateData);
            
            if (newComponent) {
              // Check if we have a target column (inner-section column)
              if (currentTargetColumn) {
                // Insert into the target column
                currentTargetColumn.appendChild(newComponent);
                
                // Hide dropzone text
                const dropzone = currentTargetColumn.querySelector('.column-dropzone');
                if (dropzone) dropzone.style.display = 'none';
                
                // Refresh and select
                refreshInsertionZones();
                updateStructurePanel();
                selectComponent(newComponent);
                
                showSuccessNotification('Section Inserted!', 'The section template has been inserted into the column.');
                closeInsertSectionTemplateModal();
                
                // Reset target
                currentTargetColumn = null;
                return;
              }
              
              // Check if we have a target inner-section (legacy)
              if (targetInnerSectionComponent) {
                // Insert into the first column of the target inner-section
                const content = targetInnerSectionComponent.querySelector('.inner-section-component');
                if (content) {
                  const columns = content.querySelectorAll('.inner-column');
                  if (columns.length > 0) {
                    // Add to first column
                    columns[0].appendChild(newComponent);
                    
                    // Hide dropzone text
                    const dropzone = columns[0].querySelector('.column-dropzone');
                    if (dropzone) dropzone.style.display = 'none';
                    
                    // Refresh and select
                    refreshInsertionZones();
                    updateStructurePanel();
                    selectComponent(newComponent);
                    
                    showSuccessNotification('Section Inserted!', 'The section template has been inserted into the inner-section.');
                    closeInsertSectionTemplateModal();
                    
                    // Reset target
                    targetInnerSectionComponent = null;
                    return;
                  }
                }
              }
              
              // Add to main page if no target column
              const page = document.getElementById('page');
              const dropzone = page.querySelector('.dropzone');
              if (dropzone) {
                page.insertBefore(newComponent, dropzone);
                dropzone.style.display = 'none';
              } else {
                page.appendChild(newComponent);
              }
              
              // Refresh and select
              refreshInsertionZones();
              updateStructurePanel();
              selectComponent(newComponent);
              
              showSuccessNotification('Section Inserted!', 'The section template has been successfully inserted into your page.');
              closeInsertSectionTemplateModal();
              
              // Reset target
              targetInnerSectionComponent = null;
            } else {
              showErrorNotification('Insert Failed', 'Unable to create section from template data.');
            }
          } else {
            showErrorNotification('Load Failed', data.message || 'Unable to load section template.');
          }
        })
        .catch(error => {
          console.error('Error:', error);
          showErrorNotification('Insert Failed', 'Unable to insert section template. Please try again.');
        });
    }

    // Helper function to create component from data
    function createComponentFromData(data) {
      console.log('Creating component from data:', data);
      
      if (!data || (!data.componentType && !data.type)) return null;
      
      const type = data.componentType || data.type;
      const component = createComponent(type);
    component.dataset.visibility = data.visibility || 'both';
      
      if (!component) {
        console.error('Failed to create component of type:', type);
        return null;
      }
      
      const content = component.querySelector('.component-content') || 
                      component.querySelector('.inner-section-component') ||
                      component.querySelector('[class*="-preview"]') ||
                      component.querySelector('[class*="-component"]');
      
      // Apply common styles
      if (content && data.style) {
        Object.keys(data.style).forEach(key => {
          if (data.style[key]) {
            content.style[key] = data.style[key];
          }
        });
      }
      
      // Handle specific component types
      switch(type) {
        case 'inner-section':
          if (data.innerSectionData && content) {
            const sectionData = data.innerSectionData;
            content._innerSectionData = sectionData;
                        // Ensure visibility is present on data for panel defaults
                        content._innerSectionData.visibility = data.visibility || sectionData.visibility || 'both';
            
            // Update columns first
            if (content.updateColumns) {
              content.updateColumns(sectionData.columns || 2);
            }
            
            // Apply background styling
            if (sectionData.backgroundColor) {
              content.style.backgroundColor = sectionData.backgroundColor;
            }
            
                        if (sectionData.backgroundType === 'image' && sectionData.backgroundImage) {
                            content.style.backgroundImage = `linear-gradient(#000,#000c 18%), url(${sectionData.backgroundImage})`;
                            content.style.backgroundPosition = '0 0, 50%';
                            content.style.backgroundSize = 'auto, cover';
                            content.style.backgroundAttachment = 'scroll, scroll';
                        }
                        // Apply video background via shared helper
                        if (content.updateBackground) {
                            content.updateBackground();
                        }
            
            // Apply padding, margin, borders
            if (sectionData.padding) content.style.padding = sectionData.padding;
            if (sectionData.margin) content.style.margin = sectionData.margin;
            if (sectionData.border) content.style.border = sectionData.border;
            if (sectionData.borderRadius) content.style.borderRadius = sectionData.borderRadius;
            
            // Apply gap
            if (sectionData.gap && content.updateGap) {
              content.updateGap(sectionData.gap);
            }
            
            // Apply full-width mode
            if (sectionData.fullWidth && content.renderInnerSection) {
              content.renderInnerSection();
            }
            
            // Update section label
            const label = content.querySelector('.section-label');
            if (label) {
              const columns = sectionData.columns || 2;
              const fullWidthText = sectionData.fullWidth ? ' - FULL WIDTH' : '';
              label.textContent = `Inner Section (${columns} Column${columns > 1 ? 's' : ''})${fullWidthText}`;
              
              if (sectionData.fullWidth) {
                label.style.backgroundColor = '#007bff';
                label.style.color = '#fff';
              }
            }
            
            // Add nested components recursively
            if (data.nestedComponents && Array.isArray(data.nestedComponents)) {
              const columns = content.querySelectorAll('.inner-column');
              console.log('Processing nested components:', data.nestedComponents.length, 'columns');
              
              data.nestedComponents.forEach((columnComps, columnIndex) => {
                console.log(`Column ${columnIndex} has ${columnComps ? columnComps.length : 0} components`);
                
                if (columns[columnIndex] && Array.isArray(columnComps)) {
                  columnComps.forEach(compData => {
                    console.log('Creating nested component:', compData);
                    const nestedComp = createComponentFromData(compData);
                    if (nestedComp) {
                      columns[columnIndex].appendChild(nestedComp);
                      
                      // Hide dropzone text
                      const dropzone = columns[columnIndex].querySelector('.column-dropzone');
                      if (dropzone) dropzone.style.display = 'none';
                    }
                  });
                }
              });
            }
          }
          break;
        
        case 'video-background':
          if (data.videoData && content) {
            content._videoData = data.videoData;
            // TODO: Apply video data to component if needed
          }
          break;
        
        case 'slider':
          if (data.sliderData && content) {
            content._sliderData = data.sliderData;
          }
          break;
        
        case 'gallery':
          if (data.galleryData && content) {
            content._galleryData = data.galleryData;
          }
          break;
        
        case 'image':
          if (data.imageData && content) {
            content._imageData = data.imageData;
          }
          break;
        
        case 'invest-cta':
          if (data.investCtaData && content) {
            content._investCtaData = data.investCtaData;
          }
          break;
        
        case 'newsletter':
          if (data.newsletterData && content) {
            content.newsletterData = data.newsletterData;
          }
          break;
        
        case 'text-images':
          if (data.textImagesData && content) {
            content._textImagesData = data.textImagesData;
          }
          break;
        
        case 'feature-grid':
          if (data.featureGridData && content) {
            content._featureGridData = data.featureGridData;
          }
          break;
        
        case 'text':
          if (data.html && content) {
            // Find the inner text-content div and update it
            const textContentDiv = content.querySelector('[id^="text-content-"]');
            if (textContentDiv) {
              textContentDiv.innerHTML = data.html;
              console.log('Text deserialized into text-content div:', data.html);
            } else {
              content.innerHTML = data.html;
              console.log('Text deserialized into content wrapper (fallback):', data.html);
            }
          }
          break;
        
        case 'section-title':
          if (data.html && content) {
            // Find the inner section-title-content div and update it
            const sectionTitleDiv = content.querySelector('[id^="section-title-content-"]');
            if (sectionTitleDiv) {
              sectionTitleDiv.innerHTML = data.html;
              console.log('Section title deserialized into section-title-content div:', data.html);
            } else {
              content.innerHTML = data.html;
              console.log('Section title deserialized into content wrapper (fallback):', data.html);
            }
          }
          break;
        
        default:
          if (data.html && content) {
            content.innerHTML = data.html;
          }
      }
      
      // Trigger re-render for the component
      if (content && typeof content.render === 'function') {
        content.render();
      }
      
      return component;
    }

    // Close modals when clicking outside
    document.addEventListener('click', function(event) {
      const saveModal = document.getElementById('saveAsTemplateModal');
      const applyModal = document.getElementById('applyTemplateModal');
      const saveSectionModal = document.getElementById('saveSectionTemplateModal');
      const insertSectionModal = document.getElementById('insertSectionTemplateModal');
      
      if (event.target === saveModal) {
        closeSaveAsTemplateModal();
      }
      if (event.target === applyModal) {
        closeApplyTemplateModal();
      }
      if (event.target === saveSectionModal) {
        closeSaveSectionTemplateModal();
      }
      if (event.target === insertSectionModal) {
        closeInsertSectionTemplateModal();
      }
    });

    window.onload = function() {

        const id = document.getElementById('page_id').value;

        fetch('/admins/page/load/'+id)
            .then(res => res.json())
            .then(data => {
            console.log('Raw page data loaded:', data);
            if (data && data.state) {
                let state = data.state;
                if (typeof state === 'string') {
                    try {
                        state = JSON.parse(state);
                        console.log('Parsed state:', state);
                    } catch (e) {
                        alert('Failed to parse saved page data.');
                        return;
                    }
                }
                deserializeBuilder(state);
                // Apply responsive CSS after loading
                updateResponsiveCSS();
                // Initialize device preview functionality
                initDevicePreview();
                // Initialize form data capture
                initFormDataCapture();
                // Initialize SortableJS for all columns after page loads
                setTimeout(() => {
                    initializeAllColumnSortables();
                    console.log('SortableJS initialized for loaded page');
                    // Initialize insertion zones for existing components
                    refreshInsertionZones();
                    console.log('Insertion zones initialized');
                    
                    // Initialize history manager and save initial state
                    historyManager.clear();
                    historyManager.saveState('Page loaded');
                    console.log('History manager initialized');
                }, 500);
            } else {
                console.log('No saved page found.');
                // Initialize device preview even if no saved page
                initDevicePreview();
                // Initialize form data capture
                initFormDataCapture();
                // Initialize insertion zones for empty page
                setTimeout(() => {
                    refreshInsertionZones();
                    
                    // Initialize history manager for empty page
                    historyManager.clear();
                    historyManager.saveState('Empty page loaded');
                    console.log('History manager initialized for empty page');
                }, 100);
            }
            })
            .catch(err => {
                console.error('Load failed:', err);
                alert('Load failed');
            });
            
        // Initialize page background color to match canvas
        const page = document.getElementById('page');
        if (page && page.style.backgroundColor) {
            const currentBgColor = page.style.backgroundColor;
            updatePageBackground(currentBgColor);
            const colorInput = document.getElementById('pageBackgroundColor');
            if (colorInput) {
                // Convert rgb to hex if needed
                const rgbToHex = (rgb) => {
                    if (rgb.startsWith('#')) return rgb;
                    const match = rgb.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
                    if (match) {
                        const r = parseInt(match[1]);
                        const g = parseInt(match[2]);
                        const b = parseInt(match[3]);
                        return '#' + [r, g, b].map(x => x.toString(16).padStart(2, '0')).join('');
                    }
                    return rgb;
                };
                colorInput.value = rgbToHex(currentBgColor);
            }
        }
    };

    // Add keyboard shortcuts for undo/redo
    document.addEventListener('keydown', function(e) {
        // Ctrl+Z for undo
        if (e.ctrlKey && e.key === 'z' && !e.shiftKey) {
            e.preventDefault();
            undoLastAction();
        }
        // Ctrl+Y or Ctrl+Shift+Z for redo
        else if (e.ctrlKey && (e.key === 'y' || (e.key === 'z' && e.shiftKey))) {
            e.preventDefault();
            redoLastAction();
        }
    });

    // Restore the showTab function (regression fix)
    function showTab(tabId) {
        // Hide all tab contents
        document.querySelectorAll('.tab-section').forEach(tab => {
            tab.style.display = 'none';
        });
        // Remove active class from all tab buttons
        document.querySelectorAll('.sidebar-tab-btn').forEach(btn => {
            btn.classList.remove('active');
        });
        // Show the selected tab content
        const tabContent = document.getElementById(tabId);
        if (tabContent) tabContent.style.display = 'block';
        // Add active class to the clicked button
        event.target.classList.add('active');
    }

    // Initialize pageData global variable if it doesn't exist
    if (!window.pageData) {
        window.pageData = {
            background_color: '{{ $data->background_color ?? "#ffffff" }}'
        };
    }
    
    console.log('[INIT] window.pageData initialized:', window.pageData);

    // Add a synchronization watchdog that ensures color input always reflects pageData
    (function setupColorSyncWatchdog() {
        const colorInput = document.getElementById('pageBackgroundColor');
        if (!colorInput) {
            console.warn('[COLOR SYNC] Color input not found');
            return;
        }
        
        // Watch for any changes to pageData.background_color and sync the input
        const originalPageData = window.pageData;
        let lastSyncedColor = originalPageData?.background_color;
        
        // Periodic check every 500ms to catch any async updates
        setInterval(() => {
            if (window.pageData && window.pageData.background_color !== lastSyncedColor) {
                console.log('[COLOR SYNC] pageData changed from', lastSyncedColor, 'to', window.pageData.background_color);
                colorInput.value = window.pageData.background_color;
                lastSyncedColor = window.pageData.background_color;
            }
        }, 500);
        
        console.log('[COLOR SYNC] Watchdog started, initial color:', lastSyncedColor);
    })();

    // Page Background Color Update Function
    function updatePageBackground(color) {
        const page = document.getElementById('page');
        const canvas = document.getElementById('canvas');
        const root = document.documentElement;
        const colorInput = document.getElementById('pageBackgroundColor');
        
        // Normalize color to hex if needed
        let normalizedColor = color;
        if (color && color.startsWith('rgb')) {
            // Convert rgb(...) to hex
            const rgbMatch = color.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
            if (rgbMatch) {
                const r = parseInt(rgbMatch[1]);
                const g = parseInt(rgbMatch[2]);
                const b = parseInt(rgbMatch[3]);
                normalizedColor = '#' + [r,g,b].map(x => x.toString(16).padStart(2,'0')).join('');
                console.log(`[updatePageBackground] Converted rgb to hex: ${color} -> ${normalizedColor}`);
            }
        }
        
        // Update page background
        if (page) {
            page.style.backgroundColor = normalizedColor;
        }
        
        // Update canvas background to match page background
        if (canvas) {
            canvas.style.backgroundColor = normalizedColor;
        }
        
        // Update CSS variable for consistent theming
        root.style.setProperty('--bg-color', normalizedColor);
        
        // Save to page data
        window.pageData.background_color = normalizedColor;
        
        // CRITICAL: Also update the color input value to ensure it reflects the current state
        if (colorInput) {
            colorInput.value = normalizedColor;
            console.log(`[updatePageBackground] Updated color input to: ${normalizedColor}`);
        }
        
        // Trigger auto-save
        if (typeof autoSavePage === 'function') {
            setTimeout(autoSavePage, 100);
        }
    }

    // FAQ Component Functions
    function toggleFaqItem(questionElement, index) {
        // Find the FAQ component
        const faqComponent = questionElement.closest('.faq-component');
        if (!faqComponent || !faqComponent._faqData) return;
        
        // Toggle the specific item
        faqComponent._faqData.questions[index].expanded = !faqComponent._faqData.questions[index].expanded;
        
        // Close all other items (accordion behavior)
        faqComponent._faqData.questions.forEach((item, i) => {
            if (i !== index) {
                item.expanded = false;
            }
        });
        
        // Re-render the FAQ
        faqComponent.renderFaq();
    }

    function addFaqQuestion() {
        if (!selectedComponent) return;
        const content = getContentElement(selectedComponent);
        if (!content._faqData) return;
        
        content._faqData.questions.push({
            question: 'New Question',
            answer: 'New Answer',
            expanded: false
        });
        
        content.renderFaq();
        updatePropertyPanel();
    }

    function removeFaqQuestion(index) {
        if (!selectedComponent) return;
        const content = getContentElement(selectedComponent);
        if (!content._faqData) return;
        
        if (confirm('Remove this FAQ question?')) {
            content._faqData.questions.splice(index, 1);
            content.renderFaq();
            updatePropertyPanel();
        }
    }

    function updateFaqQuestion(index, field, value) {
        if (!selectedComponent) return;
        const content = getContentElement(selectedComponent);
        if (!content._faqData) return;
        
        content._faqData.questions[index][field] = value;
        content.renderFaq();
    }

    function updateFaqStyle(property, value) {
        if (!selectedComponent) return;
        const content = getContentElement(selectedComponent);
        if (!content._faqData) return;
        
        content._faqData[property] = value;
        content.renderFaq();
    }

    // Disqus component functions
    function updateDisqusField(field, value) {
        if (!selectedComponent) return;
        const content = getContentElement(selectedComponent);
        if (!content._disqusData) {
            content._disqusData = {
                shortname: '',
                identifier: '',
                title: '',
                url: '',
                showInPreview: true
            };
        }
        
        content._disqusData[field] = value;
        content.renderDisqus();
        
        // Update the property panel to reflect changes
        updatePropertyPanel();
    }

    // Simple Comments component functions
    function updateSimpleCommentsField(field, value) {
        if (!selectedComponent) return;
        const content = getContentElement(selectedComponent);
        if (!content._simpleCommentsData) {
            content._simpleCommentsData = {
