                sortOrder: 'newest',
                backgroundColor: '#ffffff',
                borderColor: '#e0e0e0',
                textColor: '#333333',
                buttonColor: '#007bff'
            };
        }
        
        content._simpleCommentsData[field] = value;
        content.renderSimpleComments();
        
        // Update the property panel to reflect changes
